import { createClient } from '@supabase/supabase-js'
import * as dotenv from 'dotenv'
dotenv.config()

const supabaseUrl = process.env.VITE_SUPABASE_URL
const supabaseAnonKey = process.env.VITE_SUPABASE_ANON_KEY

if (!supabaseUrl || !supabaseAnonKey) {
  console.error("Missing environment variables!")
  process.exit(1)
}

const supabase = createClient(supabaseUrl, supabaseAnonKey)

async function createMasterAdmin() {
  console.log("Creating Master Admin account...")

  const { data, error } = await supabase.auth.signUp({
    email: 'master@intellix.com',
    password: 'password123',
    options: {
      data: {
        first_name: 'Master',
        last_name: 'Admin',
        role: 'master_admin'
      }
    }
  })

  if (error) {
    console.error("Error creating master admin:", error.message)
    process.exit(1)
  }

  console.log("Master Admin created successfully in Auth.")

  // Wait a second for trigger to execute
  await new Promise(r => setTimeout(r, 1000));

  // Force update to ensure role is master_admin (bypassing any trigger race conditions)
  if (data.user?.id) {
    const { error: profileError } = await supabase
      .from('profiles')
      .update({ role: 'master_admin' })
      .eq('id', data.user.id);

    if (profileError) {
       console.error("Could not force update profile role:", profileError);
    } else {
       console.log("Profile role strictly set to master_admin.");
    }
  }

  console.log("\n--- CREDENTIALS ---")
  console.log("Email: master@intellix.com")
  console.log("Password: password123")
  console.log("-------------------")
}

createMasterAdmin()

import { createClient } from '@supabase/supabase-js'
import * as dotenv from 'dotenv'
dotenv.config()

const supabaseUrl = process.env.VITE_SUPABASE_URL
const supabaseAnonKey = process.env.VITE_SUPABASE_ANON_KEY

if (!supabaseUrl || !supabaseAnonKey) {
  console.error("Missing environment variables!")
  process.exit(1)
}

const supabase = createClient(supabaseUrl, supabaseAnonKey)

const testUsers = [
  { email: 'admin@intellix.com', password: 'password123', role: 'admin', name: 'IntelliX Admin' },
  { email: 'teacher@intellix.com', password: 'password123', role: 'teacher', name: 'Prof. Sharma' },
  { email: 'student@intellix.com', password: 'password123', role: 'student', name: 'Ayush Kumar' },
]

async function setup() {
  for (const user of testUsers) {
    console.log(`Setting up ${user.role}: ${user.email}...`)

    // 1. Sign up user
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email: user.email,
      password: user.password,
      options: {
        data: {
          first_name: user.name.split(' ')[0],
          last_name: user.name.split(' ')[1] || '',
          role: user.role
        }
      }
    })

    if (authError) {
      if (authError.message.includes('already registered')) {
        console.log(`User ${user.email} already exists. Attempting to update role...`)
        // Fallback: If user exists, we need their ID to update profile. 
        // Note: signIn is needed but might be restricted. For simplicity, we assume signup or manual fix.
      } else {
        console.error(`Error creating ${user.email}:`, authError.message)
        continue
      }
    }

    const userId = authData?.user?.id
    if (userId) {
      // 2. Explicitly set role in profiles (in case trigger hasn't fired or for existing users)
      const { error: profileError } = await supabase
        .from('profiles')
        .update({ role: user.role })
        .eq('id', userId)

      if (profileError) {
        console.error(`Error updating profile for ${user.email}:`, profileError.message)
      } else {
        console.log(`??? Success for ${user.email}`)
      }
    }
  }
  console.log("\nSetup complete! You can now log in with these credentials.")
}

setup()

import { useEffect, useRef } from 'react'

const ParticleBackground = () => {
  const canvasRef = useRef(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    let animId

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const particles = []
    const connections = []
    const COUNT = 80

    class Particle {
      constructor() {
        this.reset()
      }
      reset() {
        this.x = Math.random() * canvas.width
        this.y = Math.random() * canvas.height
        this.vx = (Math.random() - 0.5) * 0.5
        this.vy = (Math.random() - 0.5) * 0.5
        this.radius = Math.random() * 2 + 0.5
        this.alpha = Math.random() * 0.5 + 0.2
        const colors = ['191,95,255', '0,102,255', '0,245,255']
        this.color = colors[Math.floor(Math.random() * colors.length)]
      }
      update() {
        this.x += this.vx
        this.y += this.vy
        if (this.x < 0 || this.x > canvas.width) this.vx *= -1
        if (this.y < 0 || this.y > canvas.height) this.vy *= -1
      }
      draw() {
        ctx.beginPath()
        ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2)
        ctx.fillStyle = `rgba(${this.color}, ${this.alpha})`
        ctx.fill()
        ctx.shadowBlur = 10
        ctx.shadowColor = `rgba(${this.color}, 0.5)`
      }
    }

    for (let i = 0; i < COUNT; i++) {
      particles.push(new Particle())
    }

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height)

      for (let i = 0; i < particles.length; i++) {
        particles[i].update()
        particles[i].draw()

        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x
          const dy = particles[i].y - particles[j].y
          const dist = Math.sqrt(dx * dx + dy * dy)

          if (dist < 120) {
            const opacity = (1 - dist / 120) * 0.3
            ctx.beginPath()
            ctx.moveTo(particles[i].x, particles[i].y)
            ctx.lineTo(particles[j].x, particles[j].y)
            const grad = ctx.createLinearGradient(
              particles[i].x, particles[i].y,
              particles[j].x, particles[j].y
            )
            grad.addColorStop(0, `rgba(${particles[i].color}, ${opacity})`)
            grad.addColorStop(1, `rgba(${particles[j].color}, ${opacity})`)
            ctx.strokeStyle = grad
            ctx.lineWidth = 0.5
            ctx.stroke()
          }
        }
      }
      animId = requestAnimationFrame(animate)
    }

    animate()

    return () => {
      cancelAnimationFrame(animId)
      window.removeEventListener('resize', resize)
    }
  }, [])

  return (
    <canvas
      ref={canvasRef}
      id="particle-canvas"
      style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', zIndex: 0 }}
    />
  )
}

export default ParticleBackground

import { useState, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useTheme } from '../context/ThemeContext'
import { useAuth } from '../context/AuthContext'
import { supabase } from '../lib/supabase'
import { X, Send, Bot, User, Sparkles } from 'lucide-react'

// Role-based quick questions
const roleQuickQuestions = {
  student: [
    'My attendance percentage?',
    'Upcoming tests?',
    'My weak subjects?',
    'Study plan for this week',
  ],
  teacher: [
    'Class performance overview',
    'Students with low attendance',
    'Create a test strategy',
    'Suggest teaching improvements',
  ],
  admin: [
    'Institute analytics overview',
    'At-risk students',
    'Fee collection status',
    'Monthly performance report',
  ],
  master_admin: [
    'Platform-wide stats',
    'Active institutes',
    'System health check',
    'Growth metrics',
  ],
}

const AIChatbot = () => {
  const { isDark } = useTheme()
  const { role, user } = useAuth()
  const [isOpen, setIsOpen] = useState(false)
  const [messages, setMessages] = useState([
    { role: 'ai', text: 'Hello. I am the IntelliX AI Assistant. How can I support your environment today?' }
  ])
  const [input, setInput] = useState('')
  const [isTyping, setIsTyping] = useState(false)
  const [contextData, setContextData] = useState({})
  const messagesEndRef = useRef(null)

  const quickQuestions = roleQuickQuestions[role] || roleQuickQuestions.student

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  useEffect(() => {
    if (isOpen && user) {
      fetchContextData()
    }
  }, [isOpen, user])

  const fetchContextData = async () => {
    try {
      const ctx = {}
      if (role === 'student') {
        const { data: students } = await supabase.from('students').select('id, name, batch_students(batch_id)').eq('profile_id', user.id)
        if (students?.[0]) {
          const student = students[0]
          ctx.studentName = student.name
          const { data: attendance } = await supabase.from('attendance').select('status').eq('student_id', student.id)
          const total = attendance?.length || 0
          const present = attendance?.filter(a => a.status === 'present').length || 0
          ctx.attendance = total ? `${((present / total) * 100).toFixed(1)}%` : 'No records'
        }
      }
      setContextData(ctx)
    } catch (err) {
      console.error('Context fetch error:', err)
    }
  }

  const sendMessageToAI = async (text) => {
    const q = text || input.trim()
    if (!q) return
    setMessages(prev => [...prev, { role: 'user', text: q }])
    setInput('')
    setIsTyping(true)
    try {
      const { sendMessage } = await import('../services/aiService')
      const response = await sendMessage(q, messages, role || 'student', contextData)
      setMessages(prev => [...prev, { role: 'ai', text: response }])
    } catch {
      setMessages(prev => [...prev, { role: 'ai', text: 'Connection interrupted. Please verify connectivity.' }])
    } finally {
      setIsTyping(false)
    }
  }

  return (
    <>
      {/* Premium Triger Button */}
      <motion.button
        id="ai-chatbot-btn"
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        transition={{ delay: 1, duration: 0.5 }}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-8 right-8 z-50 w-14 h-14 rounded-2xl flex items-center justify-center shadow-2xl transition-all duration-300 ${
          isDark 
            ? 'bg-black border border-white/10 text-white hover:bg-neutral-900' 
            : 'bg-black border border-black/10 text-white'
        }`}
      >
        <AnimatePresence mode="wait">
          {isOpen ? (
            <motion.div key="close" initial={{ rotate: -90, opacity: 0 }} animate={{ rotate: 0, opacity: 1 }} exit={{ rotate: 90, opacity: 0 }}>
              <X size={20} strokeWidth={1.5} />
            </motion.div>
          ) : (
            <motion.div key="open" initial={{ rotate: 90, opacity: 0 }} animate={{ rotate: 0, opacity: 1 }} exit={{ rotate: -90, opacity: 0 }}>
              <Sparkles size={20} strokeWidth={1.5} />
            </motion.div>
          )}
        </AnimatePresence>
      </motion.button>

      {/* Subtle Chat Panel */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            id="ai-chatbot-panel"
            initial={{ opacity: 0, y: 20, scale: 0.98 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.98 }}
            transition={{ duration: 0.4, ease: [0.19, 1, 0.22, 1] }}
            className={`fixed bottom-24 sm:bottom-28 right-4 sm:right-8 z-[90] w-[calc(100vw-32px)] sm:w-[380px] rounded-[2rem] border overflow-hidden backdrop-blur-xl transition-all duration-300 flex flex-col shadow-2xl ${
              isDark ? 'bg-black/95 border-white/[0.08]' : 'bg-white/95 border-gray-200'
            }`}
            style={{ height: '500px', maxHeight: 'calc(100vh - 120px)' }}
          >
            {/* Background Grid Texture */}
            <div 
              className="absolute inset-0 pointer-events-none opacity-20"
              style={{
                backgroundImage: `linear-gradient(to right, ${isDark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.05)'} 1px, transparent 1px), 
                                  linear-gradient(to bottom, ${isDark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.05)'} 1px, transparent 1px)`,
                backgroundSize: '40px 40px',
              }}
            />

            {/* Header */}
            <div className={`relative px-6 py-5 border-b flex-shrink-0 ${isDark ? 'border-white/[0.05]' : 'border-gray-100'}`}>
              <div className="flex items-center justify-between">
                <div>
                  <h3 className={`text-lg font-serif italic ${isDark ? 'text-white' : 'text-gray-900'}`}>
                    IntelliX <span className="not-italic font-sans font-bold text-xs uppercase tracking-widest text-purple-400 opacity-60 ml-1">AI</span>
                  </h3>
                  <div className="flex items-center gap-1.5 mt-0.5">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    <p className={`text-[10px] font-medium tracking-tight uppercase opacity-40 ${isDark ? 'text-white' : 'text-black'}`}>
                      Operational ?? System Engine
                    </p>
                  </div>
                </div>
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${isDark ? 'bg-white/5 border border-white/10 text-white/40' : 'bg-black/5 text-black/40'}`}>
                  <Sparkles size={18} strokeWidth={1.5} />
                </div>
              </div>
            </div>

            {/* Messages Container */}
            <div className="relative flex-1 overflow-y-auto px-6 py-6 space-y-6 scrollbar-hide">
              {messages.map((msg, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.05 }}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div
                    className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                      msg.role === 'user'
                        ? isDark ? 'bg-white/10 text-white' : 'bg-black text-white'
                        : isDark ? 'bg-white/[0.03] border border-white/[0.05] text-gray-300' : 'bg-gray-50 border border-gray-100 text-gray-700'
                    }`}
                  >
                    {msg.text}
                  </div>
                </motion.div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                  <div className={`px-5 py-4 rounded-2xl ${isDark ? 'bg-white/[0.03] border border-white/[0.05]' : 'bg-gray-50'}`}>
                    <div className="flex gap-1.5">
                      {[0, 1, 2].map(d => (
                        <motion.div
                          key={d}
                          className={`w-1.5 h-1.5 rounded-full ${isDark ? 'bg-white/20' : 'bg-black/20'}`}
                          animate={{ opacity: [0.3, 1, 0.3] }}
                          transition={{ duration: 1, repeat: Infinity, delay: d * 0.2 }}
                        />
                      ))}
                    </div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Actions & Input */}
            <div className={`relative p-6 pt-2 pb-6 border-t flex-shrink-0 ${isDark ? 'border-white/[0.05]' : 'border-gray-100'}`}>
              {/* Quick Prompt Grid */}
              <div className="flex flex-wrap gap-2 mb-6">
                {quickQuestions.map((q) => (
                  <button
                    key={q}
                    onClick={() => sendMessageToAI(q)}
                    className={`text-[10px] font-bold tracking-tight uppercase px-3 py-1.5 rounded-lg border transition-all duration-300 ${
                      isDark
                        ? 'bg-white/5 border-white/5 text-gray-500 hover:border-purple-500/30 hover:text-purple-300'
                        : 'bg-black/5 border-black/5 text-gray-500 hover:border-black/20 hover:text-black'
                    }`}
                  >
                    {q}
                  </button>
                ))}
              </div>

              {/* Precise Input Field */}
              <div className="flex gap-3">
                <input
                  type="text"
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && sendMessageToAI()}
                  placeholder="Engine query..."
                  className={`flex-1 text-xs px-4 py-3 rounded-xl outline-none transition-all duration-300 ${
                    isDark
                      ? 'bg-white/[0.05] border border-white/[0.05] text-white placeholder-gray-600 focus:border-white/20'
                      : 'bg-gray-50 border border-gray-100 text-gray-900 placeholder-gray-400 focus:border-black/20'
                  }`}
                />
                <button
                  onClick={() => sendMessageToAI()}
                  className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all duration-300 ${
                    isDark ? 'bg-white text-black hover:bg-gray-200' : 'bg-black text-white hover:bg-gray-800'
                  }`}
                >
                  <Send size={16} strokeWidth={2} />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}

export default AIChatbot

import { useEffect, useRef } from 'react'
import { motion } from 'framer-motion'
import { useTheme } from '../context/ThemeContext'

const AIVisualization = () => {
  const { isDark } = useTheme()
  const canvasRef = useRef(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    let animId

    canvas.width = canvas.offsetWidth * window.devicePixelRatio
    canvas.height = canvas.offsetHeight * window.devicePixelRatio
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio)

    const W = canvas.offsetWidth
    const H = canvas.offsetHeight

    const nodeColors = ['#BF5FFF', '#0066FF', '#00F5FF', '#7C3AED', '#06B6D4']

    const layers = [
      { x: 0.1, count: 4 },
      { x: 0.3, count: 6 },
      { x: 0.5, count: 8 },
      { x: 0.7, count: 6 },
      { x: 0.9, count: 4 },
    ]

    const nodes = []

    layers.forEach((layer, li) => {
      const spacing = H / (layer.count + 1)
      for (let i = 0; i < layer.count; i++) {
        nodes.push({
          x: layer.x * W,
          y: spacing * (i + 1),
          layer: li,
          radius: 4 + Math.random() * 3,
          color: nodeColors[li % nodeColors.length],
          pulse: Math.random() * Math.PI * 2,
          pulseSpeed: 0.02 + Math.random() * 0.02,
          active: false,
          activeCooldown: 0,
        })
      }
    })

    const connections = []
    for (let i = 0; i < nodes.length; i++) {
      for (let j = 0; j < nodes.length; j++) {
        if (nodes[j].layer === nodes[i].layer + 1) {
          connections.push({ from: i, to: j, progress: 0, active: false, speed: 0.005 + Math.random() * 0.01 })
        }
      }
    }

    let tick = 0
    const signals = []

    const fireRandomSignal = () => {
      const fromNodes = nodes.filter(n => n.layer === 0)
      const fromNode = fromNodes[Math.floor(Math.random() * fromNodes.length)]
      const fromIdx = nodes.indexOf(fromNode)
      const conns = connections.filter(c => c.from === fromIdx)
      if (conns.length) {
        const conn = conns[Math.floor(Math.random() * conns.length)]
        signals.push({ conn, progress: 0, color: fromNode.color })
      }
    }

    const animate = () => {
      ctx.clearRect(0, 0, W, H)
      tick++

      if (tick % 60 === 0) fireRandomSignal()

      // Update signals
      for (let i = signals.length - 1; i >= 0; i--) {
        signals[i].progress += 0.015
        if (signals[i].progress >= 1) {
          // Activate destination node and propagate
          const destIdx = signals[i].conn.to
          nodes[destIdx].active = true
          nodes[destIdx].activeCooldown = 20

          if (nodes[destIdx].layer < 4) {
            const nextConns = connections.filter(c => c.from === destIdx)
            if (nextConns.length) {
              const nextConn = nextConns[Math.floor(Math.random() * nextConns.length)]
              signals.push({ conn: nextConn, progress: 0, color: signals[i].color })
            }
          }
          signals.splice(i, 1)
        }
      }

      // Draw connections
      connections.forEach(conn => {
        const from = nodes[conn.from]
        const to = nodes[conn.to]
        ctx.beginPath()
        ctx.moveTo(from.x, from.y)
        ctx.lineTo(to.x, to.y)
        ctx.strokeStyle = isDark ? 'rgba(255,255,255,0.04)' : 'rgba(0,0,0,0.06)'
        ctx.lineWidth = 0.5
        ctx.stroke()
      })

      // Draw signal particles
      signals.forEach(sig => {
        const from = nodes[sig.conn.from]
        const to = nodes[sig.conn.to]
        const x = from.x + (to.x - from.x) * sig.progress
        const y = from.y + (to.y - from.y) * sig.progress

        ctx.beginPath()
        ctx.arc(x, y, 3, 0, Math.PI * 2)
        ctx.fillStyle = sig.color
        ctx.fill()
        ctx.fill()
      })

      // Draw nodes
      nodes.forEach(node => {
        node.pulse += node.pulseSpeed
        const pulseFactor = 0.8 + 0.2 * Math.sin(node.pulse)
        const r = node.radius * pulseFactor

        if (node.activeCooldown > 0) {
          node.activeCooldown--
          if (node.activeCooldown === 0) node.active = false
        }



        // Node circle
        ctx.beginPath()
        ctx.arc(node.x, node.y, r, 0, Math.PI * 2)
        ctx.fillStyle = node.active ? node.color : node.color + '80'
        ctx.fill()
      })

      animId = requestAnimationFrame(animate)
    }

    animate()

    return () => cancelAnimationFrame(animId)
  }, [isDark])

  return (
    <section id="ai" className={`section-padding ${isDark ? 'bg-[#080810]' : 'bg-gray-50'}`}>
      <div className="container-fluid">
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          {/* Left content */}
          <motion.div
            initial={{ opacity: 0, x: -40 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
          >
            <div className="inline-flex items-center gap-2 bg-purple-500/10 border border-purple-500/20 px-4 py-2 rounded-full mb-6">
              <span className="text-purple-400 text-sm font-semibold">???? Neural AI Engine</span>
            </div>
            <h2 className={`text-4xl md:text-5xl font-black mb-6 ${isDark ? 'text-white' : 'text-gray-900'}`}>
              IntelliX AI Thinks{' '}
              <span className="text-gradient">Like Your Best Analyst</span>
            </h2>
            <p className={`text-lg leading-relaxed mb-8 ${isDark ? 'text-gray-400' : 'text-gray-600'}`}>
              Our neural AI engine continuously analyzes thousands of data points 
              from your institute ??? attendance patterns, test scores, payment behavior, 
              class engagement ??? and surfaces the insights that matter most.
            </p>

