const RegisterPage = () => {
  const { isDark, toggleTheme } = useTheme()
  const navigate = useNavigate()

  const [form, setForm] = useState({ fullName: '', email: '', password: '', phone: '', role: 'student', instituteCode: '', subject: '' })
  const [showPassword, setShowPassword] = useState(false)
  const [errors, setErrors] = useState({})
  const [loading, setLoading] = useState(false)
  const [submitted, setSubmitted] = useState(false)

  const validate = () => {
    const e = {}
    if (!form.fullName.trim()) e.fullName = 'Full Name is required'
    if (!form.email.trim()) e.email = 'Email is required'
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) e.email = 'Enter a valid email address'
    if (!form.password) e.password = 'Password is required'
    else if (form.password.length < 6) e.password = 'Password must be at least 6 characters'
    if (!form.phone.trim()) e.phone = 'Phone number is required'
    else if (!/^\+?[\d\s\-]{10,15}$/.test(form.phone.trim())) e.phone = 'Enter a valid phone number'
    if (!form.instituteCode.trim()) e.instituteCode = 'Institute Code is required'
    if (form.role === 'teacher' && !form.subject.trim()) e.subject = 'Subject is required for teachers'
    return e
  }

