import { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { CheckCircle, AlertCircle, ArrowRight, BookOpen } from 'lucide-react'
import { joinBatch } from '../../services/batchService'
import { useAuth } from '../../context/AuthContext'

const JoinBatch = () => {
  const { code } = useParams()
  const navigate = useNavigate()
  const { profile, role } = useAuth()

  const [joinCode, setJoinCode] = useState(code || '')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState(false)
  const [batchName, setBatchName] = useState('')

  useEffect(() => {
    // Only students can join batches this way
    if (role !== 'student') {
      navigate('/dashboard')
    }
  }, [role, navigate])

  const handleJoin = async (e) => {
    e?.preventDefault()
    if (!joinCode.trim()) {
      setError('Please enter a valid join code')
      return
    }

    setLoading(true)
    setError('')

    try {
      const batch = await joinBatch(joinCode.trim().toUpperCase(), profile.id, profile.institute_id)
      setBatchName(batch.name)
      setSuccess(true)

      // Auto redirect to dashboard after a delay
      setTimeout(() => {
        navigate('/dashboard')
      }, 3000)
    } catch (err) {
      console.error(err)
      setError(err.message || 'Failed to join batch. Please check the code and try again.')
    } finally {
      setLoading(false)
    }
  }

  // If there's a code in the URL, optionally auto-submit
  useEffect(() => {
    if (code && profile) {
      handleJoin()
    }
    // eslint-disable-next-line
  }, [code, profile])

  if (role !== 'student') return null

  return (
    <div className="max-w-md mx-auto mt-12">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-3xl p-8 shadow-xl relative overflow-hidden"
      >
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-purple-500 to-blue-500" />

        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-purple-500/10 text-purple-400 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-purple-500/20">
            <BookOpen className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Join a Subject</h1>
          <p className="text-[var(--text-secondary)] text-sm mt-2">
            Enter the code provided by your teacher to access your materials and tests.
          </p>
        </div>

        {success ? (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center space-y-4"
          >
            <div className="w-16 h-16 bg-green-500/10 text-green-500 flex items-center justify-center rounded-full mx-auto">
              <CheckCircle className="w-8 h-8" />
            </div>
            <div>
              <h3 className="text-lg font-bold text-[var(--text-primary)]">Successfully Joined!</h3>
              <p className="text-[var(--text-secondary)] text-sm mt-1">
                You are now enrolled in <span className="font-semibold text-[var(--color-purple)]">{batchName}</span>
              </p>
            </div>
            <p className="text-xs text-[var(--text-secondary)] animate-pulse">
              Redirecting to dashboard...
            </p>
          </motion.div>
        ) : (
          <form onSubmit={handleJoin} className="space-y-6">
            <div>
              <label className="block text-sm font-semibold text-[var(--text-secondary)] mb-2 uppercase tracking-wide">
                Join Code
              </label>
              <input
                type="text"
                value={joinCode}
                onChange={(e) => {
                  setJoinCode(e.target.value)
                  if (error) setError('')
                }}
                placeholder="e.g. ABC123"
                className="w-full text-center text-3xl tracking-[0.2em] font-mono px-4 py-4 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)] focus:border-[var(--color-purple)] text-[var(--text-primary)] uppercase outline-none transition-colors"
                maxLength={8}
                autoFocus
              />
              {error && (
                <motion.p
                  initial={{ opacity: 0, y: -5 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="flex items-center justify-center gap-1.5 text-red-500 text-sm mt-3 font-medium"
                >
                  <AlertCircle className="w-4 h-4" />
                  {error}
                </motion.p>
              )}
            </div>

            <motion.button
              type="submit"
              disabled={loading || !joinCode}
              whileHover={!loading && joinCode ? { scale: 1.02 } : {}}
              whileTap={!loading && joinCode ? { scale: 0.98 } : {}}
              className="w-full h-12 flex items-center justify-center gap-2 bg-[var(--color-purple)] text-white rounded-xl font-bold border border-white/10 shadow-lg shadow-purple-500/20 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
            >
              {loading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <>
                  Join Subject
                  <ArrowRight className="w-4 h-4" />
                </>
              )}
            </motion.button>
          </form>
        )}
      </motion.div>
    </div>
  )
}

export default JoinBatch

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Trophy, RefreshCw } from 'lucide-react'
import { Select } from '../../components/ui/FormField'
import { useAuth } from '../../context/AuthContext'
import { supabase } from '../../lib/supabase'
import toast from 'react-hot-toast'
import { useAppQuery } from '../../hooks/useAppQuery'
import { CardSkeleton } from '../../components/ui/Skeletons'

const LeaderboardPage = () => {
  const { user, role } = useAuth()
  const { data: initialData, loading: initialLoading } = useAppQuery(`leaderboard-init-${role}-${user?.id}`, async () => {
    if (!user) return { batches: [] }
    let query = supabase.from('batches').select('id, name').order('name')
    if (role === 'teacher') query = query.eq('teacher_id', user.id)
    if (role === 'student') {
      const { data: batchStudents } = await supabase.from('batch_students').select('batch_id').eq('student_id', user.id)
      const batchIds = (batchStudents || []).map(bs => bs.batch_id)
      if (batchIds.length > 0) query = query.in('id', batchIds)
      else return { batches: [] }
    }
    const { data } = await query
    return { batches: data || [] }
  }, { enabled: !!user })

  useEffect(() => {
    if (initialData?.batches?.length > 0 && !selectedBatch) {
      setSelectedBatch(initialData.batches[0].id)
    }
  }, [initialData])

  const batches = initialData?.batches || []
  const isInitialLoading = initialLoading && !initialData
  const [selectedBatch, setSelectedBatch] = useState('')
  const [tests, setTests] = useState([])
  const [selectedTest, setSelectedTest] = useState('')
  const [leaderboard, setLeaderboard] = useState([])
  const [loading, setLoading] = useState(false)
  const [refreshing, setRefreshing] = useState(false)


  useEffect(() => {
    const fetchTests = async () => {
      if (!selectedBatch) return
      try {
        const { data } = await supabase
          .from('tests')
          .select('id, title')
          .eq('batch_id', selectedBatch)
          .eq('status', 'published')
          .order('date', { ascending: false })
        
        setTests(data || [])
        if (data?.length > 0) setSelectedTest(data[0].id)
        else setSelectedTest('')
      } catch (err) {
        console.error('Error fetching tests:', err)
      }
    }
    fetchTests()
  }, [selectedBatch])

  const fetchLeaderboard = async () => {
    if (!selectedTest) {
      setLeaderboard([])
      return
    }
    setRefreshing(true)
    try {
      // PART 1 & 2: CORRECT QUERY LOGIC - Fetch all results for selected_test_id
      const { data, error } = await supabase
        .from('results')
        .select(`
          student_id, 
          marks, 
          students!inner(name, email), 
          tests!inner(total_marks)
        `)
        .eq('test_id', selectedTest)
      
      if (error) throw error

      // PART 3: SORT LEADERBOARD by marks DESC
      const sorted = (data || [])
        .map((r) => ({
          student_id: r.student_id,
          name: r.students?.name || 'Unknown',
          email: r.students?.email,
          totalMarks: r.marks,
          totalPossible: r.tests?.total_marks || 100,
          percentage: r.tests?.total_marks ? ((r.marks / r.tests.total_marks) * 100).toFixed(1) : 0
        }))
        .sort((a, b) => b.totalMarks - a.totalMarks)
        // PART 4: RANK CALCULATION
        .map((s, i) => ({ ...s, rank: i + 1 }))

      setLeaderboard(sorted)
    } catch (err) {
      console.error(err)
      toast.error('Failed to load leaderboard')
    } finally {
      setRefreshing(false)
      setLoading(false)
    }
  }

  useEffect(() => {
    if (!selectedTest) {
      setLeaderboard([])
      setLoading(false)
      return
    }
    setLoading(true)
    fetchLeaderboard()
  }, [selectedTest])

  // Realtime subscription for live updates
  useEffect(() => {
    if (!selectedBatch) return

    const channel = supabase
      .channel('leaderboard-realtime')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'results' },
        () => {
          fetchLeaderboard()
        }
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [selectedBatch])

  const getRankStyle = (rank, isCurrentUser) => {
    if (isCurrentUser) return 'from-purple-500/30 to-purple-500/10 border-purple-500 shadow-lg shadow-purple-500/20'
    if (rank === 1) return 'from-amber-500/20 to-amber-500/5 border-amber-500/30 shadow-lg shadow-amber-500/10'
    if (rank === 2) return 'from-slate-400/20 to-slate-400/5 border-slate-400/30 shadow-lg shadow-slate-400/10'
    if (rank === 3) return 'from-orange-600/20 to-orange-600/5 border-orange-600/30 shadow-lg shadow-orange-600/10'
    return 'bg-[var(--bg-card)] border-[var(--border-subtle)]'
  }

  const getRankIcon = (rank) => {
    if (rank === 1) return <span className="text-3xl">????</span>
    if (rank === 2) return <span className="text-3xl">????</span>
    if (rank === 3) return <span className="text-3xl">????</span>
    return <span className="text-sm font-bold opacity-40">#{rank}</span>
  }

  const batchOptions = batches.map((b) => ({ value: b.id, label: b.name }))
  const testOptions = tests.map((t) => ({ value: t.id, label: t.title }))

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <motion.h1 
            initial={{ opacity: 0, x: -10 }} 
            animate={{ opacity: 1, x: 0 }} 
            className="text-3xl font-bold text-[var(--text-primary)] tracking-tight"
          >
            Leaderboard
          </motion.h1>
          <p className="text-[var(--text-secondary)] text-sm mt-1 font-medium">Batch rankings and top performers ??? Updates in real-time</p>
        </div>
        <button
          onClick={fetchLeaderboard}
          disabled={refreshing || !selectedTest}
          className="flex items-center gap-2 px-4 py-2 rounded-xl bg-[var(--bg-surface)] border border-[var(--border-subtle)] text-[var(--text-secondary)] hover:text-[var(--text-primary)] text-sm font-medium transition-all"
        >
          <RefreshCw className={`w-4 h-4 ${refreshing ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-w-2xl">
        <div className="bg-[var(--bg-card)] p-4 rounded-2xl border border-[var(--border-subtle)] shadow-sm">
          <Select label="Select Batch" options={batchOptions} value={selectedBatch} onChange={(e) => setSelectedBatch(e.target.value)} />
        </div>
        <div className="bg-[var(--bg-card)] p-4 rounded-2xl border border-[var(--border-subtle)] shadow-sm">
          <Select 
            label="Select Test" 
            options={testOptions} 
            value={selectedTest} 
            onChange={(e) => setSelectedTest(e.target.value)} 
            disabled={!selectedBatch || tests.length === 0}
          />
        </div>
      </div>

      {!selectedBatch ? (
        <div className="text-center py-20 bg-[var(--bg-surface)]/50 rounded-3xl border border-dashed border-[var(--border-subtle)]">
          <p className="text-[var(--text-secondary)] font-medium">Please select a batch to view leaderboard</p>
        </div>
      ) : tests.length === 0 ? (
        <div className="text-center py-20 bg-[var(--bg-surface)]/50 rounded-3xl border border-dashed border-[var(--border-subtle)]">
          <p className="text-[var(--text-secondary)] font-medium">No published tests found for this batch</p>
        </div>
      ) : (isInitialLoading || loading) ? (
        <div className="space-y-4 max-w-4xl">
          {[...Array(6)].map((_, i) => <CardSkeleton key={i} />)}
        </div>
      ) : leaderboard.length === 0 ? (
        <div className="text-center py-20 bg-[var(--bg-surface)]/50 rounded-3xl border border-dashed border-[var(--border-subtle)]">
          <Trophy className="w-16 h-16 mx-auto mb-4 text-[var(--text-secondary)] opacity-20" />
          <p className="text-[var(--text-secondary)] font-medium text-lg">No attempts yet for this test</p>
        </div>
      ) : (
        <div className="space-y-4 max-w-4xl">
          {leaderboard.map((entry, i) => {
            const isCurrentUser = entry.student_id === user.id
            return (
              <motion.div
                key={entry.student_id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.05 }}
                className={`flex items-center justify-between px-6 py-5 rounded-2xl border transition-all hover:scale-[1.01] bg-gradient-to-r ${getRankStyle(entry.rank, isCurrentUser)}`}
              >
                <div className="flex items-center gap-6">
                  <div className="w-12 h-12 flex items-center justify-center shrink-0">
                    {getRankIcon(entry.rank)}
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                      <p className="text-base font-bold text-[var(--text-primary)]">{entry.name}</p>
                      {isCurrentUser && (
                        <span className="px-2 py-0.5 rounded-full bg-purple-500 text-[10px] font-bold text-white uppercase tracking-wider">You</span>
                      )}
                    </div>
                    <p className="text-xs text-[var(--text-secondary)] font-medium mt-0.5">
                      Scored {entry.totalMarks} out of {entry.totalPossible}
                    </p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-2xl font-black text-[var(--text-primary)]">{entry.percentage}%</p>
                  <p className="text-[10px] uppercase tracking-widest font-bold text-[var(--text-secondary)]">score</p>
                </div>
              </motion.div>
            )
          })}
        </div>
      )}
    </div>
  )
}

export default LeaderboardPage

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { FileText, Users, ClipboardCheck, BookOpen, Layers } from 'lucide-react'
import { supabase } from '../../lib/supabase'
import { useTheme } from '../../context/ThemeContext'
import { useAppQuery } from '../../hooks/useAppQuery'
import { CardSkeleton } from '../../components/ui/Skeletons'

const LogsPage = () => {
  const { isDark } = useTheme()
  const { data: logsData, loading: logsLoading } = useAppQuery('activity-logs', async () => {
    // Fetch recent activities from multiple tables
    const [studentsRes, testsRes, attendanceRes, materialsRes, batchesRes] = await Promise.all([
      supabase.from('students').select('id, name, created_at').order('created_at', { ascending: false }).limit(10),
      supabase.from('tests').select('id, title, created_at').order('created_at', { ascending: false }).limit(10),
      supabase.from('attendance').select('id, date, status, created_at, students(name)').order('created_at', { ascending: false }).limit(10),
      supabase.from('materials').select('id, title, created_at').order('created_at', { ascending: false }).limit(10),
      supabase.from('batches').select('id, name, created_at').order('created_at', { ascending: false }).limit(10),
    ])

    const combined = []
    ;(studentsRes.data || []).forEach(s => {
      combined.push({ id: `student-${s.id}`, type: 'student', icon: Users, color: 'purple', description: `Student "${s.name}" was added`, timestamp: s.created_at })
    })
    ;(testsRes.data || []).forEach(t => {
      combined.push({ id: `test-${t.id}`, type: 'test', icon: FileText, color: 'blue', description: `Test "${t.title}" was created`, timestamp: t.created_at })
    })
    ;(attendanceRes.data || []).forEach(a => {
      combined.push({ id: `attendance-${a.id}`, type: 'attendance', icon: ClipboardCheck, color: a.status === 'present' ? 'green' : 'red', description: `${a.students?.name || 'Student'} marked ${a.status} on ${new Date(a.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}`, timestamp: a.created_at })
    })
    ;(materialsRes.data || []).forEach(m => {
      combined.push({ id: `material-${m.id}`, type: 'material', icon: BookOpen, color: 'cyan', description: `Material "${m.title}" was uploaded`, timestamp: m.created_at })
    })
    ;(batchesRes.data || []).forEach(b => {
      combined.push({ id: `batch-${b.id}`, type: 'batch', icon: Layers, color: 'amber', description: `Batch "${b.name}" was created`, timestamp: b.created_at })
    })

    combined.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp))
    return combined.slice(0, 30)
  })

  const loading = logsLoading && !logsData
  const logs = logsData || []


  const colorMap = {
    purple: 'bg-purple-500/10 text-purple-500',
    blue: 'bg-blue-500/10 text-blue-500',
    green: 'bg-green-500/10 text-green-500',
    red: 'bg-red-500/10 text-red-500',
    cyan: 'bg-cyan-500/10 text-cyan-500',
    amber: 'bg-amber-500/10 text-amber-500',
  }

  if (loading) {
    return (
      <div className="space-y-4">
        {[...Array(8)].map((_, i) => <CardSkeleton key={i} />)}
      </div>
    )
  }

  return (
    <div className="space-y-8">
      <div>
        <motion.h1
          initial={{ opacity: 0, x: -10 }}
          animate={{ opacity: 1, x: 0 }}
          className="text-3xl font-bold text-[var(--text-primary)] tracking-tight"
        >
          Activity Logs
        </motion.h1>
        <p className="text-[var(--text-secondary)] text-sm mt-1 font-medium">
          Recent system activity across all modules
        </p>
      </div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface)] p-6 shadow-sm"
      >
        {logs.length === 0 ? (
          <p className="text-[var(--text-secondary)] text-sm py-8 text-center">No activity recorded yet</p>
        ) : (
          <div className="space-y-1">
            {logs.map((log, i) => {
              const Icon = log.icon
              return (
                <motion.div
                  key={log.id}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.02 }}
                  className="flex items-center gap-4 px-4 py-3 rounded-xl hover:bg-[var(--bg-app)] transition-colors group"
                >
                  <div className={`w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0 ${colorMap[log.color] || colorMap.purple}`}>
                    <Icon className="w-4 h-4" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm text-[var(--text-primary)] font-medium truncate">{log.description}</p>
                  </div>
                  <span className="text-xs text-[var(--text-secondary)] whitespace-nowrap flex-shrink-0">
                    {new Date(log.timestamp).toLocaleString(undefined, {
                      month: 'short',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit',
                    })}
                  </span>
                </motion.div>
              )
            })}
          </div>
        )}
      </motion.div>
    </div>
  )
}

export default LogsPage

import { useState, useEffect, useRef } from 'react'
import { motion } from 'framer-motion'
import { Upload, FileText, Trash2, Download, Search } from 'lucide-react'
import { Select } from '../../components/ui/FormField'
import { getMaterials, uploadMaterial, deleteMaterial } from '../../services/materialService'
import { useAuth } from '../../context/AuthContext'
import { supabase } from '../../lib/supabase'
import { useAppQuery } from '../../hooks/useAppQuery'
import { CardSkeleton } from '../../components/ui/Skeletons'

const MaterialsPage = () => {
  const { user, role } = useAuth()
  const { data: initialData, loading: initialLoading, refetch: refetchInitial } = useAppQuery(`materials-init-${role}-${user?.id}`, async () => {
    if (!user) return { batches: [], materials: [] }
    
    let batchData = []
    if (role === 'student') {
      const { data: enrolledBatches } = await supabase.from('batch_students').select('batch_id').eq('student_id', user.id)
      if (enrolledBatches && enrolledBatches.length > 0) {
        const batchIds = enrolledBatches.map(eb => eb.batch_id)
        const { data } = await supabase.from('batches').select('id, name').in('id', batchIds).order('name')
        batchData = data || []
      }
    } else {
      let query = supabase.from('batches').select('id, name').order('name')
      if (role === 'teacher') query = query.eq('teacher_id', user.id)
      const { data } = await query
      batchData = data || []
    }

    let mats = []
    if (role === 'student') {
      if (batchData.length > 0) {
        const batchIds = batchData.map(b => b.id)
        mats = await getMaterials(batchIds)
      }
    } else {
      mats = await getMaterials(undefined)
    }

    return { batches: batchData, materials: mats }
  }, { enabled: !!user })

  useEffect(() => {
    if (initialData?.materials) {
      setMaterials(initialData.materials)
    }
    if (initialData?.batches) {
      setBatches(initialData.batches)
    }
  }, [initialData])

  const batches = initialData?.batches || []
  const [materials, setMaterials] = useState(initialData?.materials || [])
  const [loading, setLoading] = useState(false)
  const [selectedBatch, setSelectedBatch] = useState('')
  const [search, setSearch] = useState('')
  const [title, setTitle] = useState('')
  const [uploadBatch, setUploadBatch] = useState('')
  const [uploading, setUploading] = useState(false)
  const fileRef = useRef(null)
  const canUpload = role !== 'student'
  
  const isInitialLoading = initialLoading && !initialData

  const fetchData = async () => {
    setLoading(true)
    try {
      const mats = await getMaterials(selectedBatch || undefined)
      setMaterials(mats)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { 
    if (selectedBatch) fetchData() 
    else if (initialData?.materials) setMaterials(initialData.materials)
  }, [selectedBatch])

  const handleUpload = async () => {
    const file = fileRef.current?.files?.[0]
    if (!file || !title.trim() || !uploadBatch) return
    setUploading(true)
    try {
      await uploadMaterial(file, uploadBatch, title, user.id)
      setTitle('')
      setUploadBatch('')
      if (fileRef.current) fileRef.current.value = ''
      fetchData()
    } catch (err) {
      console.error(err)
      alert('Upload failed: ' + err.message)
    } finally {
      setUploading(false)
    }
  }

  const handleDelete = async (mat) => {
    if (!confirm(`Delete "${mat.title}"?`)) return
    try {
      await deleteMaterial(mat.id, mat.file_url)
      fetchData()
    } catch (err) {
      console.error(err)
    }
  }

  const filtered = materials.filter(
    (m) => m.title.toLowerCase().includes(search.toLowerCase())
  )

  const batchOptions = batches.map((b) => ({ value: b.id, label: b.name }))

  return (
    <div className="space-y-8">
      <div>
        <motion.h1 
          initial={{ opacity: 0, x: -10 }} 
          animate={{ opacity: 1, x: 0 }} 
          className="text-3xl font-bold text-[var(--text-primary)] tracking-tight"
        >
          Study Materials
        </motion.h1>
        <p className="text-[var(--text-secondary)] text-sm mt-1 font-medium">
          {canUpload ? 'Upload and manage study materials for your batches' : 'Access your shared study materials and resources'}
        </p>
      </div>

      {/* Upload Section */}
      {canUpload && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface)] p-6 shadow-sm"
        >
          <div className="flex items-center gap-3 mb-6">
            <div className="p-2 rounded-lg bg-[var(--color-purple)]/10">
              <Upload className="w-5 h-5 text-[var(--color-purple)]" />
            </div>
            <h2 className="text-lg font-bold text-[var(--text-primary)]">Upload Material</h2>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            <div>
              <label className="block text-sm font-semibold text-[var(--text-secondary)] mb-1.5 uppercase tracking-wider">Title</label>
              <input
                type="text"
                placeholder="Enter document title"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full px-4 py-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm placeholder-[var(--text-secondary)]/50 outline-none focus:border-[var(--color-purple)] focus:bg-[var(--bg-app)] transition-all"
              />
            </div>
            <Select
              label="Select Batch"
              placeholder={batchOptions.length > 0 ? "Target batch" : "No batches available"}
              options={batchOptions}
              value={uploadBatch}
              onChange={(e) => setUploadBatch(e.target.value)}
              disabled={batchOptions.length === 0}
            />
            <div>
              <label className="block text-sm font-semibold text-[var(--text-secondary)] mb-1.5 uppercase tracking-wider">File (PDF/DOC)</label>
              <input
                ref={fileRef}
                type="file"
                accept=".pdf,.doc,.docx,.ppt,.pptx,.xlsx"
                className="w-full text-xs text-[var(--text-secondary)] file:mr-4 file:py-2.5 file:px-5 file:rounded-xl file:border-0 file:text-xs file:font-bold file:bg-[var(--color-purple)]/10 file:text-[var(--color-purple)] hover:file:bg-[var(--color-purple)]/20 file:cursor-pointer transition-all"
              />
            </div>
            <div className="flex items-end">
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={handleUpload}
                disabled={uploading || !title.trim() || !uploadBatch}
                className="w-full flex items-center justify-center gap-2 px-6 py-3 rounded-xl bg-[var(--color-purple)] text-white text-sm font-bold disabled:opacity-50 shadow-lg shadow-purple-500/20 active:scale-95 transition-all"
              >
                {uploading ? (
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <Upload className="w-5 h-5" />
                )}
                {uploading ? 'Uploading...' : 'Publish Material'}
              </motion.button>
            </div>
          </div>
        </motion.div>
      )}

      {/* Filters */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 bg-[var(--bg-card)] p-6 rounded-2xl border border-[var(--border-subtle)] shadow-sm">
        <div className="flex-1">
          <Select
            label="Filter by Batch"
            placeholder="All Batches"
            options={[{ value: '', label: 'All Batches' }, ...batchOptions]}
            value={selectedBatch}
            onChange={(e) => setSelectedBatch(e.target.value)}
          />
        </div>
        <div className="flex-1">
          <label className="block text-sm font-semibold text-[var(--text-secondary)] mb-1.5 uppercase tracking-wider">Quick Search</label>
          <div className="relative">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-secondary)]" />
            <input
              type="text"
              placeholder="Find materials by title..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm placeholder-[var(--text-secondary)]/50 outline-none focus:border-[var(--color-purple)] focus:bg-[var(--bg-app)] transition-all"
            />
          </div>
        </div>
      </div>

      {/* Materials Grid */}
      {isInitialLoading || loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {[...Array(8)].map((_, i) => <CardSkeleton key={i} />)}
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-20 bg-[var(--bg-surface)]/50 rounded-3xl border border-dashed border-[var(--border-subtle)]">
          <FileText className="w-16 h-16 mx-auto mb-4 text-[var(--text-secondary)] opacity-20" />
          <p className="text-[var(--text-secondary)] font-medium text-lg">No materials found matching your criteria</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {filtered.map((mat, i) => (
            <motion.div
              key={mat.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
              className="group rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface)] p-5 flex flex-col hover:border-[var(--color-purple)]/30 hover:shadow-xl hover:shadow-purple-500/5 transition-all"
            >
              <div className="flex items-start gap-3 mb-4">
                <div className="p-3 rounded-xl bg-[var(--color-purple)]/10 text-[var(--color-purple)] group-hover:bg-[var(--color-purple)] group-hover:text-white transition-all">
                  <FileText className="w-6 h-6" />
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="text-sm font-bold text-[var(--text-primary)] truncate transition-colors group-hover:text-[var(--color-purple)]">{mat.title}</h3>
                  <p className="text-[10px] font-bold text-[var(--text-secondary)] uppercase tracking-wider mt-1">{mat.batches?.name || 'PUBLIC'}</p>
                </div>
              </div>
              <div className="mb-6 flex-1">
                 <p className="text-xs text-[var(--text-secondary)] font-medium flex items-center gap-1.5 flex-wrap leading-relaxed">
                   <span className="w-1 h-1 rounded-full bg-[var(--border-subtle)]" />
                   Published {mat.profiles?.first_name ? `by ${mat.profiles.first_name} ${mat.profiles.last_name || ''} ` : ''}on {new Date(mat.created_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <a
                  href={mat.file_url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)] text-[var(--text-primary)] hover:bg-[var(--color-purple)] hover:text-white hover:border-transparent transition-all text-xs font-bold"
                >
                  <Download className="w-3.5 h-3.5" /> Get File
                </a>
                {canUpload && (
                  <button
                    onClick={() => handleDelete(mat)}
                    className="p-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)] text-[var(--text-secondary)] hover:bg-red-500/10 hover:text-red-500 hover:border-red-500/20 transition-all active:scale-90"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                )}
              </div>
            </motion.div>
          ))}
        </div>
      )}
    </div>
  )
}

