  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-[var(--bg-surface)] p-6 rounded-2xl border border-[var(--border-subtle)] shadow-sm">
        <div>
          <motion.h1 
            initial={{ opacity: 0, x: -10 }} 
            animate={{ opacity: 1, x: 0 }} 
            className="text-3xl font-bold text-[var(--text-primary)] tracking-tight"
          >
            Teachers
          </motion.h1>
          <p className="text-[var(--text-secondary)] mt-1 font-medium">Manage teaching staff for your institute</p>
        </div>
        <button
        onClick={() => handleOpenAdd()}
          className="flex items-center px-5 py-2.5 bg-[var(--color-purple)] text-white rounded-xl hover:opacity-90 transition-all font-semibold shadow-lg shadow-purple-500/20 active:scale-95"
        >
          <Plus className="w-5 h-5 mr-2" />
          Add Teacher
        </button>
      </div>

      <div className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl overflow-hidden shadow-sm">
        <div className="p-5 border-b border-[var(--border-subtle)] flex justify-between items-center bg-[var(--bg-app)]/50">
          <div className="relative w-80">
            <Search className="absolute left-3.5 top-1/2 transform -translate-y-1/2 text-[var(--text-secondary)] w-4 h-4" />
            <input
              type="text"
              placeholder="Search teachers..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-[var(--bg-app)] border border-[var(--border-subtle)] text-[var(--text-primary)] placeholder-[var(--text-secondary)] rounded-xl focus:outline-none focus:border-[var(--color-purple)] transition-all text-sm font-medium"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-[var(--bg-app)]/50 text-[var(--text-secondary)] text-xs uppercase tracking-wider">
              <tr>
                <th className="px-6 py-5 font-bold">Name</th>
                <th className="px-6 py-5 font-bold">Subject</th>
                <th className="px-6 py-5 font-bold">Phone</th>
                <th className="px-6 py-5 font-bold">Email</th>
                <th className="px-6 py-5 font-bold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-[var(--border-subtle)]">
              {filteredTeachers.map((teacher) => (
                <tr key={teacher.id} className="hover:bg-[var(--bg-app)] transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="font-semibold text-[var(--text-primary)]">{teacher.name}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center text-[var(--text-primary)] font-medium">
                      <div className="p-1.5 rounded-lg bg-[var(--color-purple)]/10 text-[var(--color-purple)] mr-2.5">
                        <BookOpen className="w-3.5 h-3.5" />
                      </div>
                      {teacher.subject || '-'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-[var(--text-secondary)] font-medium">
                    <div className="flex items-center gap-2">
                      <Phone className="w-3.5 h-3.5 text-[var(--color-purple)]" />
                      {teacher.phone || '-'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-[var(--text-secondary)] font-medium">
                    <div className="flex items-center gap-2">
                      <Mail className="w-3.5 h-3.5 text-blue-400" />
                      {teacher.email || '-'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right space-x-3 whitespace-nowrap">
                    <button
                      onClick={() => handleOpenEdit(teacher)}
                      className="text-gray-400 hover:text-white transition"
                    >
                      <Edit2 className="w-4 h-4 inline" />
                    </button>
                    <button 
                      onClick={() => handleDelete(teacher.id)}
                      className="text-red-400 hover:text-red-300 transition"
                    >
                      <Trash2 className="w-4 h-4 inline" />
                    </button>
                  </td>
                </tr>
              ))}
              {filteredTeachers.length === 0 && (
                <tr>
                  <td colSpan="5" className="px-6 py-8 text-center text-gray-500">
                    No teachers found. Click 'Add Teacher' to create one.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && typeof document !== 'undefined' && createPortal(
        <div className="fixed inset-0 w-screen h-screen bg-black/50 backdrop-blur-sm flex items-center justify-center z-50">
          <div className={`${isDark ? 'bg-gray-900 border-gray-800 text-white' : 'bg-white border-gray-200 text-gray-900'} border p-6 rounded-xl w-full max-w-md shadow-2xl relative z-50`}>
          <h2 className="text-xl font-bold mb-4">{editingTeacher ? 'Edit Teacher' : 'Add New Teacher'}</h2>
            <form onSubmit={handleSubmit} className="space-y-4 max-h-[85vh] overflow-y-auto pr-2">
              <div>
                <label className={`block text-sm font-medium ${isDark ? 'text-gray-400' : 'text-gray-600'} mb-1`}>Full Name</label>
                <input
                  required
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className={`w-full px-4 py-2 ${isDark ? 'bg-gray-800 border-gray-700 text-white focus:border-[var(--color-purple)]' : 'bg-gray-50 border-gray-200 text-gray-900 focus:border-[var(--color-purple)]/50'} border rounded-lg focus:outline-none transition-all`}
                />
              </div>
              {/* Email ??? shown in edit mode for updating the teachers table record */}
              {editingTeacher && (
                <div>
                  <label className={`block text-sm font-medium ${isDark ? 'text-gray-400' : 'text-gray-600'} mb-1`}>Email / Gmail</label>
                  <input
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    placeholder="teacher@gmail.com"
                    className={`w-full px-4 py-2 ${isDark ? 'bg-gray-800 border-gray-700 text-white focus:border-[var(--color-purple)]' : 'bg-gray-50 border-gray-200 text-gray-900 focus:border-[var(--color-purple)]/50'} border rounded-lg focus:outline-none transition-all`}
                  />
                </div>
              )}
              {/* Email & Password ??? only for new teacher creation */}
              {!editingTeacher && (
                <>
                  <div>
                    <label className={`block text-sm font-medium ${isDark ? 'text-gray-400' : 'text-gray-600'} mb-1`}>Email Address *</label>
                    <input
                      required
                      type="email"
                      value={formData.email}
                      onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                      className={`w-full px-4 py-2 ${isDark ? 'bg-gray-800 border-gray-700 text-white focus:border-[var(--color-purple)]' : 'bg-gray-50 border-gray-200 text-gray-900 focus:border-[var(--color-purple)]/50'} border rounded-lg focus:outline-none transition-all`}
                    />
                  </div>
                  <div>
                    <label className={`block text-sm font-medium ${isDark ? 'text-gray-400' : 'text-gray-600'} mb-1`}>Password *</label>
                    <input
                      required
                      type="password"
                      value={formData.password}
                      onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                      placeholder="Minimum 6 characters"
                      className={`w-full px-4 py-2 ${isDark ? 'bg-gray-800 border-gray-700 text-white focus:border-[var(--color-purple)]' : 'bg-gray-50 border-gray-200 text-gray-900 focus:border-[var(--color-purple)]/50'} border rounded-lg focus:outline-none transition-all`}
                    />
                  </div>
                </>
              )}
              <div>
                <label className={`block text-sm font-medium ${isDark ? 'text-gray-400' : 'text-gray-600'} mb-1`}>Subject Expertise</label>
                <input
                  required
                  type="text"
                  placeholder="e.g. Advanced Mathematics"
                  value={formData.subject}
                  onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                  className={`w-full px-4 py-2 ${isDark ? 'bg-gray-800 border-gray-700 text-white focus:border-[var(--color-purple)]' : 'bg-gray-50 border-gray-200 text-gray-900 focus:border-[var(--color-purple)]/50'} border rounded-lg focus:outline-none transition-all`}
                />
              </div>
              {/* Phone ??? editable in both add and edit mode */}
              <div>
                <label className={`block text-sm font-medium ${isDark ? 'text-gray-400' : 'text-gray-600'} mb-1`}>Phone Number</label>
                <input
                  type="tel"
                  placeholder="e.g. +91 98765 43210"
                  value={formData.phone}
                  onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                  className={`w-full px-4 py-2 ${isDark ? 'bg-gray-800 border-gray-700 text-white focus:border-[var(--color-purple)]' : 'bg-gray-50 border-gray-200 text-gray-900 focus:border-[var(--color-purple)]/50'} border rounded-lg focus:outline-none transition-all`}
                />
              </div>
              
              <div className={`flex justify-end space-x-3 pt-4 border-t ${isDark ? 'border-gray-800' : 'border-gray-100'}`}>
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  disabled={submitting}
                  className={`px-4 py-2 ${isDark ? 'text-gray-400 hover:text-white' : 'text-gray-500 hover:text-gray-800 font-medium'} transition`}
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={submitting}
                  className="px-4 py-2 bg-[var(--color-purple)] text-white rounded-lg hover:opacity-90 transition disabled:opacity-50 flex items-center gap-2"
                >
                  {submitting && <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />}
                  {submitting ? 'Saving...' : editingTeacher ? 'Update Teacher' : 'Save Teacher'}
                </button>
              </div>
            </form>
          </div>
        </div>,
        document.body
      )}
    </div>
  )
}

export default TeachersPage

import { useState, useEffect, useCallback, useRef } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { motion } from 'framer-motion'
import { Clock, ChevronLeft, ChevronRight, AlertTriangle, CheckCircle2, Send, Shield, Sparkles } from 'lucide-react'
import toast from 'react-hot-toast'
import { supabase } from '../../lib/supabase'
import { useAuth } from '../../context/AuthContext'
import { generateAIFeedback } from '../../services/aiTestService'
import { TestAttemptSkeleton } from '../../components/ui/Skeletons'

const TestAttemptPage = () => {
  // 1. HOOKS
  const { testId } = useParams()
  const { user } = useAuth()
  const navigate = useNavigate()

  const [test, setTest] = useState(null)
  const [questions, setQuestions] = useState([])
  const [currentQuestion, setCurrentQuestion] = useState(0)
  const [answers, setAnswers] = useState({})
  const [timeLeft, setTimeLeft] = useState(null)
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [submitted, setSubmitted] = useState(false)
  const [result, setResult] = useState(null)
  const [violationCount, setViolationCount] = useState(0)
  const [attemptId, setAttemptId] = useState(null)

  const timerRef = useRef(null)
  const pollRef = useRef(null)
  const questionsRef = useRef([])
  const answersRef = useRef({})
  const testRef = useRef(null)
  const submittingRef = useRef(false)
  const submittedRef = useRef(false)
  const violationRef = useRef(0)
  const attemptIdRef = useRef(null)

  // Sync refs for stable access in timer/realtime callbacks
  useEffect(() => {
    questionsRef.current = questions
    answersRef.current = answers
    testRef.current = test
    submittingRef.current = submitting
    submittedRef.current = submitted
    violationRef.current = violationCount
    attemptIdRef.current = attemptId
  }, [questions, answers, test, submitting, submitted, violationCount, attemptId])

  // 2. HELPER FUNCTIONS
  const formatTime = (seconds) => {
    if (seconds === null) return '--:--'
    if (seconds <= 0) return '00:00'
    const m = Math.floor(seconds / 60)
    const s = Math.floor(seconds % 60)
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`
  }

  const getTimerColor = () => {
    if (timeLeft === null) return 'text-[var(--text-primary)]'
    if (timeLeft <= 60) return 'text-red-400 animate-pulse'
    if (timeLeft <= 300) return 'text-amber-400'
    return 'text-green-400'
  }

  // 3. SAVE ANSWERS TO DB (Persistent across refresh)
  const persistAnswers = async (newAnswers) => {
    if (!attemptIdRef.current) return
    try {
      await supabase
        .from('student_attempts')
        .update({ answers: newAnswers })
        .eq('id', attemptIdRef.current)
    } catch (err) {
      console.warn('Answer save failed (non-critical):', err)
    }
  }

  // 4. EVENT HANDLERS
  async function handleSubmit(isAutoSubmit = false, reason = '') {
    if (submittingRef.current || submittedRef.current) return
    const qList = questionsRef.current
    const ansList = answersRef.current
    const currentT = testRef.current
    if (!qList.length) return

    submittingRef.current = true
    setSubmitting(true)

    try {
      if (timerRef.current) clearInterval(timerRef.current)
      if (pollRef.current) clearInterval(pollRef.current)

      // 1. DATA VALIDATION
      if (!attemptIdRef.current) {
        // Emergency fetch attempt id if missing from state
        const { data: syncAttempt } = await supabase
          .from('student_attempts')
          .select('id, status')
          .eq('student_id', user.id)
          .eq('test_id', testId)
          .maybeSingle()
        
        if (syncAttempt) {
            if (syncAttempt.status === 'submitted' || syncAttempt.status === 'forced_end') {
                toast('Tests already submitted.')
                navigate('/dashboard')
                return
            }
            attemptIdRef.current = syncAttempt.id
        } else {
            throw new Error('Attempt Session Missing. Please refresh and try again.')
        }
      }

      const currentAttemptId = attemptIdRef.current

      // Calculate score
      let score = 0
      if (qList && qList.length > 0) {
        qList.forEach(q => {
          if (q && ansList[q.id] === q.answer) score++
        })
      }

      // 2. UPDATE ATTEMPT STATUS
      const status = reason === 'teacher_stop' ? 'forced_end' : 
                     reason === 'violation' ? 'submitted' :
                     isAutoSubmit ? 'submitted' : 'submitted'
      
      await supabase
        .from('student_attempts')
        .update({ 
          status,
          answers: ansList 
        })
        .eq('id', currentAttemptId)

      // 3. INSERT RESULT WITH RETRY
      let resultData = null
      let resultErr = null
      
      const insertResult = async () => {
        return await supabase
          .from('results')
          .insert({
            student_id: user.id,
            test_id: testId,
            marks: score,
            answers: ansList,
            submitted_at: new Date().toISOString(),
            institute_id: currentT?.institute_id,
            violation_count: violationRef.current,
          })
          .select()
          .single()
      }

      const res = await insertResult()
      resultData = res.data
      resultErr = res.error

      if (resultErr) {
        if (resultErr.code === '23505') {
          // Already exists, just fetch it
          const { data: existing } = await supabase.from('results').select('*').eq('student_id', user.id).eq('test_id', testId).single()
          setResult(existing)
        } else {
          // Retry once
          console.warn('Submission failed once, retrying...', resultErr)
          const retryRes = await insertResult()
          if (retryRes.error) throw retryRes.error
          resultData = retryRes.data
        }
      }

      if (resultData) {
        setResult(resultData)
        // Background: Generate AI Feedback
        generateAIFeedback(resultData, currentT, qList)
          .then(async (feedback) => {
            if (feedback) {
              await supabase.from('results').update({ ai_feedback: feedback }).eq('id', resultData.id)
            }
          })
          .catch(err => console.error("AI feedback gen failed:", err))
      }

      submittedRef.current = true
      setSubmitted(true)

      if (reason === 'teacher_stop') {
        toast('The teacher has ended this test.', { icon: '????' })
      } else if (reason === 'violation') {
        toast.error('??? Auto-submitted due to tab switching violations.', { duration: 6000 })
      } else if (isAutoSubmit) {
        toast('??? Time\'s up! Test auto-submitted.', { icon: '??????' })
      } else {
        toast.success(`Test submitted! Score: ${score}/${qList.length}`)
      }
    } catch (err) {
      console.error('Submit error:', err)
      toast.error('Submission failed. Please check your connection and try again.', { duration: 5000 })
      setSubmitting(false)
      submittingRef.current = false
    }
  }

  function handleOptionSelect(questionId, option) {
    setAnswers(prev => {
      const updated = { ...prev, [questionId]: option }
      // Persist to DB (fire-and-forget)
      persistAnswers(updated)
      return updated
    })
  }

  function goNext() {
    if (currentQuestion < questions.length - 1) {
      setCurrentQuestion(prev => prev + 1)
    }
  }

  function goPrev() {
    if (currentQuestion > 0) {
      setCurrentQuestion(prev => prev - 1)
    }
  }

  // 5. DATA LOADING & EFFECTS
  useEffect(() => {
    if (!user || !testId) return

    const loadData = async () => {
      try {
        setLoading(true)

        // 1. Check if already submitted
        const { data: existingResult } = await supabase
          .from('results')
          .select('*')
          .eq('student_id', user.id)
          .eq('test_id', testId)
          .maybeSingle()

        if (existingResult) {
          setResult(existingResult)
          setSubmitted(true)
          setLoading(false)
          return
        }

        // 2. Load test details
        const { data: testData, error: tErr } = await supabase
          .from('tests')
          .select('*')
          .eq('id', testId)
          .single()

        if (tErr || !testData) throw new Error('Test not found')
        setTest(testData)

        // 3. Check if test is locked (ended by teacher or past end_time)
        if (testData.end_time && new Date(testData.end_time) <= new Date()) {
          toast.error('This test has already ended.')
          navigate('/dashboard')
          return
        }

        // 4. Check if test hasn't started yet
        if (testData.start_time && new Date(testData.start_time) > new Date()) {
          toast.error('This test has not started yet.')
          navigate('/dashboard')
          return
        }

        // 5. Timer Persistence: Check or Create attempt record
        const { data: attemptData } = await supabase
          .from('student_attempts')
          .select('*')
          .eq('student_id', user.id)
          .eq('test_id', testId)
          .maybeSingle()

        let currentAttempt
        const durationSecs = (testData.duration_minutes || 30) * 60

        if (!attemptData) {
          // First time starting ??? create attempt with server-persisted ends_at
          const startedAt = new Date()
          const endsAt = new Date(startedAt.getTime() + durationSecs * 1000)

          const { data: newAttempt, error: iErr } = await supabase
            .from('student_attempts')
            .insert({
              student_id: user.id,
              test_id: testId,
              institute_id: testData.institute_id,
              ends_at: endsAt.toISOString(),
              status: 'in_progress',
              answers: {},
              violation_count: 0,
            })
            .select()
            .single()

          if (iErr) {
            console.error('student_attempts insert failed:', iErr)
            // Retry once immediately for robustness
            const { data: retryAttempt, error: rErr } = await supabase
              .from('student_attempts')
              .insert({
                student_id: user.id,
                test_id: testId,
                institute_id: testData.institute_id,
                ends_at: endsAt.toISOString(),
                status: 'in_progress',
              })
              .select().single()
            
            if (rErr) throw new Error('Failed to initialize test session. Please try again.')
            currentAttempt = retryAttempt
            setAttemptId(retryAttempt.id)
          } else {
            currentAttempt = newAttempt
            setAttemptId(newAttempt.id)
          }
        } else {
          // Resuming ??? check if already submitted
          if (attemptData.status === 'submitted' || attemptData.status === 'forced_end') {
            toast('This test was already submitted.')
            navigate('/dashboard')
            return
          }

          currentAttempt = attemptData
          setAttemptId(attemptData.id)

          // Restore saved answers
          if (attemptData.answers && Object.keys(attemptData.answers).length > 0) {
            setAnswers(attemptData.answers)
          }

          // If ends_at is missing (old record), compute it
          if (!attemptData.ends_at) {
            const endsAt = new Date(new Date(attemptData.started_at).getTime() + durationSecs * 1000)
            currentAttempt.ends_at = endsAt.toISOString()
            // Patch the DB
            if (attemptData.id) {
              await supabase.from('student_attempts').update({ ends_at: endsAt.toISOString() }).eq('id', attemptData.id)
            }
          }
        }

        // Set violation count from DB
        setViolationCount(currentAttempt.violation_count || 0)

        // 6. Load questions
        const { data: qData, error: qErr } = await supabase
          .from('questions')
          .select('*')
          .eq('test_id', testId)
          .order('sort_order', { ascending: true })

        if (qErr || !qData || qData.length === 0) throw new Error('Questions not found')
        setQuestions(qData)

        // 7. Calculate remaining time from SERVER-BASED ends_at
        const endsAtTime = new Date(currentAttempt.ends_at)
        const now = new Date()
        const remaining = Math.max(0, Math.floor((endsAtTime - now) / 1000))

        setTimeLeft(remaining)
        if (remaining <= 0) {
          handleSubmit(true)
        }

      } catch (err) {
        console.error('Loader error:', err)
        toast.error(err.message)
        navigate('/dashboard')
      } finally {
        setLoading(false)
      }
    }

    loadData()
  }, [testId, user])

  // Timer Effect ??? counts down locally but is initialized from server
  useEffect(() => {
    if (timeLeft === null || submitted || loading) return

    timerRef.current = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current)
          handleSubmit(true)
          return 0
        }
        return prev - 1
      })
    }, 1000)

    return () => clearInterval(timerRef.current)
  }, [timeLeft === null, submitted, loading])

  // Realtime Listener ??? teacher stop
  useEffect(() => {
    if (!testId || submitted || loading) return

    const channel = supabase
      .channel(`test-attempt-${testId}`)
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'tests', filter: `id=eq.${testId}` }, payload => {
        const updated = payload.new
        // If teacher forced an early end
        if (updated?.end_time && new Date(updated.end_time) <= new Date()) {
          handleSubmit(true, 'teacher_stop')
        }
      })
      .subscribe()

    // Fallback polling every 30 seconds in case Realtime misses an event
    pollRef.current = setInterval(async () => {
      if (submittedRef.current) return
      try {
        const { data: freshTest } = await supabase
          .from('tests')
          .select('end_time')
          .eq('id', testId)
          .single()
        if (freshTest?.end_time && new Date(freshTest.end_time) <= new Date()) {
          handleSubmit(true, 'teacher_stop')
        }
      } catch {}
    }, 30000)

    return () => {
      supabase.removeChannel(channel)
      if (pollRef.current) clearInterval(pollRef.current)
    }
  }, [testId, submitted, loading])

  // Anti-Cheat: Server-Persisted Tab Switch Detection
  useEffect(() => {
    if (submitted || loading || !testId) return

    const handleVisibilityChange = async () => {
      if (document.hidden && !submittedRef.current) {
        const newCount = violationRef.current + 1
        setViolationCount(newCount)

        // Persist to DB
        if (attemptIdRef.current) {
          try {
            await supabase
              .from('student_attempts')
              .update({ violation_count: newCount })
              .eq('id', attemptIdRef.current)
          } catch (err) {
            console.warn('Violation save failed:', err)
          }
        }

        if (newCount === 1) {
          toast.error('?????? WARNING: Do not switch tabs! Your next tab switch will auto-submit the test.', {
            duration: 6000,
            icon: '????',
            style: { border: '1px solid #ef4444', backgroundColor: '#450a0a', color: '#f87171' }
          })
        } else if (newCount >= 2) {
          toast.error('??? Tab switch detected again. Auto-submitting test.', {
            duration: 6000,
            icon: '????',
            style: { border: '1px solid #ef4444', backgroundColor: '#450a0a', color: '#f87171' }
          })
          handleSubmit(true, 'violation')
        }
      }
    }

    document.addEventListener('visibilitychange', handleVisibilityChange)
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange)
  }, [submitted, loading, testId, user])

  // 6. RENDER LOGIC
  if (loading) return <TestAttemptSkeleton />

  if (submitted) {
    const score = result?.marks || 0
    const total = questions.length || test?.total_marks || 0
    const pct = total ? Math.round((score / total) * 100) : 0

    return (
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="max-w-lg mx-auto py-12"
      >
        <div className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-3xl p-8 text-center shadow-xl">
          <div className={`w-20 h-20 mx-auto mb-6 rounded-2xl flex items-center justify-center ${
            pct >= 70 ? 'bg-green-500/10' : pct >= 40 ? 'bg-amber-500/10' : 'bg-red-500/10'
          }`}>
            <CheckCircle2 className={`w-10 h-10 ${
              pct >= 70 ? 'text-green-400' : pct >= 40 ? 'text-amber-400' : 'text-red-400'
            }`} />
          </div>
          <h2 className="text-2xl font-bold text-[var(--text-primary)] mb-2">Submission Successful!</h2>
          <p className="text-[var(--text-secondary)] text-sm mb-8">{test?.title}</p>

          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="p-4 rounded-2xl bg-[var(--bg-app)] border border-[var(--border-subtle)]">
              <p className="text-2xl font-bold text-[var(--text-primary)]">{score}/{total}</p>
              <p className="text-[10px] uppercase tracking-widest text-[var(--text-secondary)] mt-1 font-bold">Marks Obtained</p>
            </div>
            <div className={`p-4 rounded-2xl border ${
              pct >= 70 ? 'border-green-500/20' : pct >= 40 ? 'border-amber-500/20' : 'border-red-500/20'
            }`}>
              <p className={`text-2xl font-bold ${
                pct >= 70 ? 'text-green-400' : pct >= 40 ? 'text-amber-400' : 'text-red-400'
              }`}>{pct}%</p>
              <p className="text-[10px] uppercase tracking-widest text-[var(--text-secondary)] mt-1 font-bold">Final Score</p>
            </div>
          </div>

          {/* Violations Badge */}
          {(result?.violation_count > 0 || violationCount > 0) && (
            <div className="mb-6 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/20">
              <p className="text-xs font-bold text-red-400">
                ?????? {result?.violation_count || violationCount} Tab Switch Violation{(result?.violation_count || violationCount) > 1 ? 's' : ''} Detected
              </p>
            </div>
          )}
          <button
            onClick={() => navigate('/dashboard')}
            className="w-full py-4 rounded-xl bg-purple-500 text-white font-bold shadow-lg shadow-purple-500/20 active:scale-[0.98] transition-all"
          >
            Back to Dashboard
          </button>
        </div>
      </motion.div>
    )
  }

  if (!test || questions.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[40vh] bg-[var(--bg-surface)] rounded-3xl border border-dashed border-[var(--border-subtle)] p-12 text-center">
        <AlertTriangle className="w-12 h-12 text-amber-500 mb-4" />
        <h3 className="text-lg font-bold text-[var(--text-primary)]">Test Unavailable</h3>
        <p className="text-sm text-[var(--text-secondary)] mt-2">No question data found for this exam.</p>
        <button onClick={() => navigate('/dashboard')} className="mt-6 text-purple-400 hover:underline text-sm font-medium">Return Dashboard</button>
      </div>
    )
  }

  const q = questions[currentQuestion]
  const answeredCount = Object.keys(answers).length

  return (
    <div className="max-w-4xl mx-auto pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-4 p-4 mb-6 bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-xl bg-purple-500/10 flex items-center justify-center">
            <Clock className={`w-6 h-6 ${getTimerColor()}`} />
          </div>
          <div>
            <h1 className="text-lg font-bold text-[var(--text-primary)] leading-none">{test?.title}</h1>
            <p className="text-xs text-[var(--text-secondary)] mt-1 font-medium">
              Progress: {answeredCount} / {questions.length} Questions
            </p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {/* Violations indicator */}
          {violationCount > 0 && (
            <div className="px-3 py-1.5 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs font-bold flex items-center gap-1.5">
              <AlertTriangle className="w-3.5 h-3.5" />
              {violationCount} Violation{violationCount > 1 ? 's' : ''}
            </div>
          )}
          <div className={`px-5 py-3 rounded-xl border font-mono text-xl font-black ${
            timeLeft <= 60 ? 'bg-red-500/10 border-red-500/20 text-red-400 shadow-[0_0_15px_rgba(239,68,68,0.1)]' : 'bg-[var(--bg-app)] border-[var(--border-subtle)] text-[var(--text-primary)]'
          }`}>
            {formatTime(timeLeft)}
          </div>
          <button
            onClick={() => handleSubmit(false)}
            disabled={submitting}
            className="px-6 py-3 bg-gradient-to-r from-purple-500 to-cyan-500 text-white font-bold rounded-xl shadow-lg shadow-purple-500/20 flex items-center gap-2 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-50"
          >
            <Send className="w-4 h-4" />
            Finish
          </button>
        </div>
      </div>

      {/* Navigation Matrix */}
      <div className="flex flex-wrap gap-2 mb-8 px-2">
        {questions.map((item, idx) => (
          <button
            key={item.id}
            onClick={() => setCurrentQuestion(idx)}
            className={`w-10 h-10 rounded-xl font-bold text-xs transition-all ${
              idx === currentQuestion 
                ? 'bg-purple-500 text-white shadow-lg shadow-purple-500/30' 
                : answers[item.id] 
                  ? 'bg-green-500/20 text-green-400 border border-green-500/30' 
                  : 'bg-[var(--bg-surface)] border border-[var(--border-subtle)] text-[var(--text-secondary)] hover:border-[var(--border-strong)]'
            }`}
          >
            {idx + 1}
          </button>
        ))}
      </div>

      {/* Question Card */}
      <motion.div
        key={currentQuestion}
        initial={{ opacity: 0, x: 20 }}
        animate={{ opacity: 1, x: 0 }}
        className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-[2.5rem] p-8 shadow-sm"
      >
        <div className="flex items-start gap-5 mb-10">
          <span className="flex-shrink-0 w-12 h-12 rounded-2xl bg-purple-500/10 flex items-center justify-center text-purple-400 font-black text-xl border border-purple-500/20">
            {currentQuestion + 1}
          </span>
          <h2 className="text-lg md:text-xl font-semibold text-[var(--text-primary)] leading-relaxed pt-1">
            {q?.question}
          </h2>
        </div>

        <div className="grid gap-4 mb-10">
          {q?.options?.map((opt, oIdx) => {
            const letter = ['A', 'B', 'C', 'D'][oIdx]
            const isSelected = answers[q.id] === letter
            return (
              <button
                key={oIdx}
                onClick={() => handleOptionSelect(q.id, letter)}
                className={`flex items-center gap-5 p-5 rounded-2xl border text-left transition-all ${
                  isSelected 
                    ? 'bg-purple-500/10 border-purple-500/40 shadow-[0_4px_15px_rgba(168,85,247,0.1)]' 
                    : 'bg-[var(--bg-app)] border-[var(--border-subtle)] hover:border-[var(--border-strong)]'
                }`}
              >
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-sm border transition-all ${
                  isSelected ? 'bg-purple-500 text-white border-purple-500' : 'bg-[var(--bg-surface)] text-[var(--text-secondary)] border-[var(--border-subtle)]'
                }`}>
                  {letter}
                </div>
                <span className={`text-sm md:text-base font-medium ${isSelected ? 'text-purple-400' : 'text-[var(--text-primary)]'}`}>
                  {opt}
                </span>
              </button>
            )
          })}
        </div>

        <div className="flex items-center justify-between pt-8 border-t border-[var(--border-subtle)]">
          <button
            onClick={goPrev}
            disabled={currentQuestion === 0}
            className="flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-bold text-[var(--text-secondary)] hover:bg-[var(--bg-app)] disabled:opacity-30 transition-all"
          >
            <ChevronLeft className="w-5 h-5" /> Previous
          </button>

          <div className="text-xs font-bold text-[var(--text-secondary)] tracking-widest uppercase opacity-40">
            Question {currentQuestion + 1} of {questions.length}
          </div>

          {currentQuestion < questions.length - 1 ? (
            <button
              onClick={goNext}
              className="flex items-center gap-2 px-8 py-3 bg-[var(--color-purple)] text-white font-bold rounded-xl shadow-lg shadow-purple-500/20 hover:scale-[1.02] active:scale-[0.98] transition-all"
            >
              Next <ChevronRight className="w-5 h-5" />
            </button>
          ) : (
            <button
              onClick={() => handleSubmit(false)}
              disabled={submitting}
              className="flex items-center gap-2 px-8 py-3 bg-gradient-to-r from-purple-500 to-cyan-500 text-white font-bold rounded-xl shadow-lg shadow-purple-500/20 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-50"
            >
              <Send className="w-5 h-5" /> Submit Exam
            </button>
          )}
        </div>
      </motion.div>

      {/* Safety Banner */}
      <div className="mt-6 flex items-center justify-center gap-3 py-4 rounded-2xl bg-amber-500/5 border border-amber-500/10">
        <Shield className="w-4 h-4 text-amber-500/60" />
        <p className="text-[10px] md:text-xs font-bold text-amber-500/60 uppercase tracking-widest">
          Intelligent Proctoring Active ??? Secure Session ??? Do Not Refresh
        </p>
      </div>
    </div>
  )
}

export default TestAttemptPage

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Plus, FileText, Trash2, Search, ListOrdered, Sparkles, Brain, Clock, CheckCircle2, FileDown, AlertTriangle } from 'lucide-react'
import jsPDF from 'jspdf'
import autoTable from 'jspdf-autotable'
import DataTable from '../../components/ui/DataTable'
import Modal from '../../components/ui/Modal'
import { Input, Select } from '../../components/ui/FormField'
import { getTests, createTest, deleteTest } from '../../services/testService'
import { getResultsByTest, upsertResults } from '../../services/resultService'
import { getStudentsByBatch } from '../../services/studentService'
import { getBatches } from '../../services/batchService'
import { useAuth } from '../../context/AuthContext'
import { supabase } from '../../lib/supabase'
import toast from 'react-hot-toast'
import AITestCreatorModal from '../../components/teacher/AITestCreatorModal'
import { useAppQuery } from '../../hooks/useAppQuery'
import { TableSkeleton } from '../../components/ui/Skeletons'

const TestsPage = () => {
  const { user, role } = useAuth()
  const { data: testsData, loading: testsLoading, refetch: refetchTests } = useAppQuery(`tests-${role}-${user?.id}`, async () => {
    if (!user) return { tests: [], batches: [] }
    
    let query = supabase.from('tests').select('id, title, date, total_marks, batch_id, is_ai_generated, start_time, end_time, batches(name), questions(id)').order('date', { ascending: false })
      
    if (role === 'teacher') {
      const { data: myBatches } = await supabase.from('batches').select('id').eq('teacher_id', user.id)
      const batchIds = (myBatches || []).map((b) => b.id)
      if (batchIds.length > 0) {
        query = query.in('batch_id', batchIds)
      } else {
        return { tests: [], batches: [] }
      }
    } else if (role === 'student') {
      const { data: studentBatches } = await supabase.from('batch_students').select('batch_id').eq('student_id', user.id)
      const studentBatchIds = (studentBatches || []).map(b => b.batch_id)
      if (studentBatchIds.length > 0) {
        query = query.in('batch_id', studentBatchIds)
      } else {
        return { tests: [], batches: [] }
      }
    }
    
    const { data: tests } = await query
    
    const { data: batchData } = role === 'teacher'
      ? await supabase.from('batches').select('id, name').eq('teacher_id', user.id)
      : await supabase.from('batches').select('id, name')

    return {
      tests: tests || [],
      batches: batchData || []
    }
  }, { enabled: !!user })

  const tests = testsData?.tests || []
  const batches = testsData?.batches || []
  const loading = testsLoading && !testsData

  const fetchData = () => refetchTests()

  useEffect(() => { fetchData() }, [])

  // Realtime updates for tests
  useEffect(() => {
    if (!user) return
    const channel = supabase
      .channel('tests-updates')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'tests' }, payload => {
        fetchData()
      })
      .subscribe()
    return () => {
      supabase.removeChannel(channel)
    }
  }, [user])

  const handleCreateTest = async () => {
    if (!form.title.trim() || !form.batch_id) return
    setSaving(true)
    try {
      await createTest({
        title: form.title,
        batch_id: form.batch_id,
        date: form.date,
        total_marks: parseInt(form.total_marks) || 100,
        created_by: user.id,
      })
      setModalOpen(false)
      setForm({ 
        title: '', 
        batch_id: '', 
        date: new Date().toLocaleDateString('en-CA'), 
        total_marks: '100' 
      })
      fetchData()
      toast.success('Test created successfully!')
    } catch (err) {
      console.error(err)
      toast.error('Failed to create test')
    } finally {
      setSaving(false)
    }
  }

  const openResults = async (test) => {
    setSelectedTest(test)
    try {
      const [students, results] = await Promise.all([
        getStudentsByBatch(test.batch_id),
        getResultsByTest(test.id),
      ])
      setTestStudents(students)
      const marksMap = {}
      results.forEach((r) => { marksMap[r.student_id] = r.marks })
      setMarks(marksMap)
      setResultsModal(true)
    } catch (err) {
      console.error(err)
      toast.error('Failed to load results')
    }
  }

  const handleSaveResults = async () => {
    if (!selectedTest) return
    setSaving(true)
    try {
      const entries = testStudents
        .filter((s) => marks[s.id] !== undefined && marks[s.id] !== '')
        .map((s) => ({
          student_id: s.id,
          test_id: selectedTest.id,
          marks: parseInt(marks[s.id]) || 0,
        }))
        .sort((a, b) => b.marks - a.marks)
        .map((entry, i) => ({ ...entry, rank: i + 1 }))

      await upsertResults(entries)
      setResultsModal(false)
      toast.success('Results saved successfully!')
    } catch (err) {
      console.error(err)
      toast.error('Failed to save results')
    } finally {
      setSaving(false)
    }
  }

  const handleDeleteTest = async (id) => {
    try {
      await deleteTest(id)
      fetchData()
      toast.success('Test deleted')
    } catch (err) {
      console.error(err)
      toast.error('Failed to delete test')
    }
  }

  const handleEndTest = async (id) => {
    try {
      const { error } = await supabase.from('tests').update({ end_time: new Date().toISOString() }).eq('id', id)
      if (error) throw error
      toast.success('Test ended successfully')
      fetchData()
    } catch (err) {
      console.error(err)
      toast.error('Failed to end test')
    }
  }

  const handleStartTest = async (id) => {
    try {
      const { error } = await supabase.from('tests').update({ start_time: new Date().toISOString() }).eq('id', id)
      if (error) throw error
      toast.success('Test started successfully')
      fetchData()
    } catch (err) {
      console.error(err)
      toast.error('Failed to start test')
    }
  }

  const filtered = tests.filter((t) => t.title.toLowerCase().includes(search.toLowerCase()))
  const canManage = role === 'teacher'          // create / delete / end / save marks
  const canView   = role === 'admin' || role === 'teacher'  // view status + results

  const columns = [
    { key: 'title', label: 'Test Title', render: (r) => (
      <div className="flex items-center gap-2">
        <span>{r.title}</span>
        {r.is_ai_generated && (
          <span className="px-1.5 py-0.5 rounded-md text-[10px] font-bold bg-purple-500/10 text-purple-400 border border-purple-500/20 flex items-center gap-0.5">
            <Sparkles className="w-2.5 h-2.5" /> AI
          </span>
        )}
      </div>
    )},
    { key: 'batch_id', label: 'Batch', render: (r) => r.batches?.name || '-' },
    { key: 'date', label: 'Date', render: (r) => new Date(r.date).toLocaleDateString() },
    { key: 'total_marks', label: 'Total Marks' },
    { key: 'questions_count', label: 'Questions', render: (r) => r.questions?.length || 0 },
  ]

  if (canView) {
    columns.push({
      key: 'status_col',
      label: 'Status',
      render: (row) => {
        const now = new Date()
        const hasQuestions = row.questions?.length > 0
        if (!hasQuestions) return <span className="text-xs text-[var(--text-secondary)]">Manual</span>
        if (row.end_time && new Date(row.end_time) < now) return <span className="text-xs text-red-400 flex items-center gap-1"><CheckCircle2 className="w-3 h-3" /> Ended</span>
        
        if (row.start_time && new Date(row.start_time) > now) {
          return (
            <div className="flex items-center gap-2">
              <span className="text-xs text-amber-400 flex items-center gap-1"><Clock className="w-3 h-3" /> Scheduled</span>
              {canManage && (
                <button
                  onClick={(e) => { e.stopPropagation(); handleStartTest(row.id) }}
                  className="px-2 py-0.5 ml-2 rounded text-[10px] font-bold bg-amber-500/10 text-amber-500 border border-amber-500/20 hover:bg-amber-500/20 transition-colors"
                >
                  Start Now
                </button>
              )}
            </div>
          )
        }
        
        return (
          <div className="flex items-center gap-2">
            <span className="text-xs text-green-400 flex items-center gap-1"><CheckCircle2 className="w-3 h-3" /> Active</span>
            {canManage && (
              <button
                onClick={(e) => { e.stopPropagation(); handleEndTest(row.id) }}
                className="px-2 py-0.5 ml-2 rounded text-[10px] font-bold bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20 transition-colors"
              >
                End Now
              </button>
            )}
          </div>
        )
      }
    })
    columns.push({
      key: 'actions',
      label: 'Actions',
      sortable: false,
      render: (row) => (
        <div className="flex items-center gap-2">
          <button
            onClick={(e) => { e.stopPropagation(); openResults(row) }}
            className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-purple-500/10 text-purple-400 hover:bg-purple-500/20 transition-colors text-xs"
          >
            <ListOrdered className="w-3.5 h-3.5" /> Results
          </button>
          {canManage && (
            <button
              onClick={(e) => { e.stopPropagation(); handleDeleteTest(row.id) }}
              className="p-1.5 rounded-lg hover:bg-white/10 text-gray-400 hover:text-red-400 transition-colors"
            >
              <Trash2 className="w-4 h-4" />
            </button>
          )}
        </div>
      ),
    })
  }

  const batchOptions = batches.map((b) => ({ value: b.id, label: b.name }))

  const downloadResultsPDF = () => {
    if (!selectedTest) return
    const batchName = selectedTest.batches?.name || 'Batch'
    const testTitle = selectedTest.title || 'Test'
    const doc = new jsPDF()

    // Styled header
    doc.setFillColor(139, 92, 246)
    doc.rect(0, 0, 220, 28, 'F')
    doc.setTextColor(255, 255, 255)
    doc.setFontSize(18)
    doc.setFont('helvetica', 'bold')
    doc.text('Results Report', 14, 18)

    // Meta
    doc.setTextColor(40, 40, 40)
    doc.setFontSize(11)
    doc.setFont('helvetica', 'normal')
    doc.text(`Test: ${testTitle}`, 14, 38)
    doc.text(`Batch: ${batchName}`, 14, 46)
    doc.text(`Date: ${selectedTest.date}  |  Total Marks: ${selectedTest.total_marks}`, 14, 54)

    // Ranked table
    const ranked = [...testStudents]
      .map(s => ({ ...s, m: parseInt(marks[s.id] ?? NaN) }))
      .sort((a, b) => (isNaN(a.m) ? 1 : isNaN(b.m) ? -1 : b.m - a.m))

    autoTable(doc, {
      startY: 62,
      head: [['Rank', 'Student Name', 'Email', 'Marks', 'Score %']],
      body: ranked.map((s, i) => [
        isNaN(s.m) ? '-' : i + 1,
        s.name || 'Unknown student',
        s.email || '-',
        isNaN(s.m) ? 'N/A' : `${s.m} / ${selectedTest.total_marks || 100}`,
        isNaN(s.m) ? '-' : Math.round((s.m / (selectedTest.total_marks || 100)) * 100) + '%',
      ]),
      styles: { fontSize: 10, cellPadding: 5 },
      headStyles: { fillColor: [139, 92, 246], textColor: 255, fontStyle: 'bold' },
      alternateRowStyles: { fillColor: [248, 245, 255] },
      didParseCell: (data) => {
        if (data.column.index === 4 && data.section === 'body') {
          const pct = parseInt(data.cell.raw)
          data.cell.styles.fontStyle = 'bold'
          data.cell.styles.textColor = pct >= 75 ? [16, 185, 129] : pct >= 50 ? [245, 158, 11] : [239, 68, 68]
        }
      },
    })

    // Page footer
    const pages = doc.internal.getNumberOfPages()
    for (let i = 1; i <= pages; i++) {
      doc.setPage(i)
      doc.setFontSize(8)
      doc.setTextColor(150)
      doc.setFont('helvetica', 'normal')
      doc.text(`Generated by IntelliX  ???  Page ${i} of ${pages}`, 14, doc.internal.pageSize.height - 8)
    }

    doc.save(`results_${testTitle}_${selectedTest.date}.pdf`)
  }

  // ?????? Admin: fetch results for a selected test ??????????????????????????????????????????????????????????????????????????????????????????
  const fetchAdminResults = async (testId) => {
    setAdminLoading(true)
    try {
      const { data } = await supabase
        .from('results')
        .select('marks, rank, violation_count, students(name, email)')
        .eq('test_id', testId)
        .order('rank', { ascending: true })
      setAdminResults(data || [])
    } catch (err) {
      console.error(err)
    } finally {
      setAdminLoading(false)
    }
  }

  const downloadAdminResultsPDF = () => {
    const testObj = tests.find(t => t.id === adminSelTest)
    const batchObj = batches.find(b => b.id === adminSelBatch)
    if (!testObj) return
    const doc = new jsPDF()

    doc.setFillColor(139, 92, 246)
    doc.rect(0, 0, 220, 28, 'F')
    doc.setTextColor(255, 255, 255)
    doc.setFontSize(18)
    doc.setFont('helvetica', 'bold')
    doc.text('Results Report', 14, 18)

    doc.setTextColor(40, 40, 40)
    doc.setFontSize(11)
    doc.setFont('helvetica', 'normal')
    doc.text(`Test: ${testObj.title}`, 14, 38)
    doc.text(`Batch: ${batchObj?.name || '-'}`, 14, 46)
    doc.text(`Date: ${testObj.date}  |  Total Marks: ${testObj.total_marks}`, 14, 54)

    autoTable(doc, {
      startY: 62,
      head: [['Rank', 'Student Name', 'Email', 'Marks', 'Score %']],
      body: adminResults.map((r) => {
        const pct = testObj.total_marks ? Math.round((r.marks / testObj.total_marks) * 100) : '-'
        return [
          r.rank ?? '-',
          r.students?.name || '-',
          r.students?.email || '-',
          `${r.marks} / ${testObj.total_marks}`,
          typeof pct === 'number' ? pct + '%' : '-',
        ]
      }),
      styles: { fontSize: 10, cellPadding: 5 },
      headStyles: { fillColor: [139, 92, 246], textColor: 255, fontStyle: 'bold' },
      alternateRowStyles: { fillColor: [248, 245, 255] },
      didParseCell: (data) => {
        if (data.column.index === 4 && data.section === 'body') {
          const pct = parseInt(data.cell.raw)
          data.cell.styles.fontStyle = 'bold'
          data.cell.styles.textColor = pct >= 75 ? [16, 185, 129] : pct >= 50 ? [245, 158, 11] : [239, 68, 68]
        }
      },
    })

    const pages = doc.internal.getNumberOfPages()
    for (let i = 1; i <= pages; i++) {
      doc.setPage(i)
      doc.setFontSize(8)
      doc.setTextColor(150)
      doc.text(`Generated by IntelliX  ???  Page ${i} of ${pages}`, 14, doc.internal.pageSize.height - 8)
    }
    doc.save(`results_${testObj.title}_${testObj.date}.pdf`)
  }
  if (loading) {
    return <TableSkeleton rows={8} cols={5} />
  }

  // ?????? Admin view: batch ??? test ??? results ?????????????????????????????????????????????????????????????????????????????????????????????????????????
  if (role === 'admin') {
    const adminBatchTests = tests.filter(t => t.batch_id === adminSelBatch)
    const adminTestObj = tests.find(t => t.id === adminSelTest)
    const selectCls = 'w-full px-4 py-2.5 rounded-xl bg-[var(--bg-app)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm outline-none focus:border-[var(--color-purple)] transition-all appearance-none cursor-pointer'
    const labelCls = 'block text-xs font-bold text-[var(--text-secondary)] uppercase tracking-wider mb-2'

    return (
      <div className="space-y-6">
        <div>
          <motion.h1 initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }}
            className="text-3xl font-bold text-[var(--text-primary)] tracking-tight">Tests &amp; Results</motion.h1>
          <p className="text-[var(--text-secondary)] text-sm mt-1 font-medium">View and download test result reports</p>
        </div>

        {/* Selectors card */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 bg-[var(--bg-card)] p-6 rounded-2xl border border-[var(--border-subtle)] shadow-sm">
          <div>
            <label className={labelCls}>Batch</label>
            <select
              value={adminSelBatch}
              onChange={(e) => { setAdminSelBatch(e.target.value); setAdminSelTest(''); setAdminResults([]) }}
              className={selectCls}
            >
              <option value="">Choose a batch</option>
              {batches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>
          <div>
            <label className={labelCls}>Test</label>
            <select
              value={adminSelTest}
              disabled={!adminSelBatch}
              onChange={async (e) => {
                const tid = e.target.value
                setAdminSelTest(tid)
                setAdminResults([])
                if (tid) await fetchAdminResults(tid)
              }}
              className={`${selectCls} disabled:opacity-40 disabled:cursor-not-allowed`}
            >
              <option value="">Choose a test</option>
              {adminBatchTests.map(t => <option key={t.id} value={t.id}>{t.title}</option>)}
            </select>
          </div>
        </div>

        {/* Results table */}
        <div className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl overflow-hidden shadow-sm">
          {adminSelTest && adminResults.length > 0 && (
            <div className="p-5 border-b border-[var(--border-subtle)] flex justify-between items-center bg-[var(--bg-app)]/50">
              <div>
                <p className="font-semibold text-[var(--text-primary)]">{adminTestObj?.title}</p>
                <p className="text-xs text-[var(--text-secondary)] mt-0.5">{adminResults.length} students &bull; Total: {adminTestObj?.total_marks} marks</p>
              </div>
              <button
                onClick={downloadAdminResultsPDF}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-[var(--color-purple)]/10 text-[var(--color-purple)] hover:bg-[var(--color-purple)]/20 transition-all text-sm font-semibold active:scale-95"
              >
                <FileDown className="w-4 h-4" /> Download PDF
              </button>
            </div>
          )}
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-[var(--bg-app)]/50 text-[var(--text-secondary)] text-xs uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-5 font-bold">Student</th>
                  <th className="px-6 py-5 font-bold">Marks</th>
                  <th className="px-6 py-5 font-bold">%</th>
                  <th className="px-6 py-5 font-bold">Rank</th>
                  <th className="px-6 py-5 font-bold">Violations</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[var(--border-subtle)]">
                {!adminSelBatch || !adminSelTest ? (
                  <tr><td colSpan="5" className="px-6 py-12 text-center text-[var(--text-secondary)] text-sm">Select a batch and test to view results</td></tr>
                ) : adminLoading ? (
                  <tr><td colSpan="5" className="px-6 py-12">
                    <TableSkeleton rows={3} cols={5} />
                  </td></tr>
                ) : adminResults.length === 0 ? (
                  <tr><td colSpan="5" className="px-6 py-12 text-center text-[var(--text-secondary)] text-sm">No results recorded for this test yet</td></tr>
                ) : (
                  adminResults.map((r, i) => {
                    const pct = adminTestObj?.total_marks ? Math.round((r.marks / adminTestObj.total_marks) * 100) : null
                    const pctColor = pct === null ? '' : pct >= 75 ? 'text-emerald-400' : pct >= 50 ? 'text-amber-400' : 'text-red-400'
                    const violations = r.violation_count || 0
                    return (
                      <tr key={i} className="hover:bg-[var(--bg-app)] transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-full bg-[var(--color-purple)]/10 text-[var(--color-purple)] flex items-center justify-center text-xs font-bold">
                              {r.students?.name?.charAt(0).toUpperCase() || '?'}
                            </div>
                            <div>
                              <p className="font-semibold text-[var(--text-primary)] text-sm">{r.students?.name || '-'}</p>
                              <p className="text-xs text-[var(--text-secondary)]">{r.students?.email || ''}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 font-bold text-[var(--text-primary)]">
                          {r.marks} <span className="text-[var(--text-secondary)] font-normal text-xs">/ {adminTestObj?.total_marks}</span>
                        </td>
                        <td className={`px-6 py-4 font-bold ${pctColor}`}>
                          {pct !== null ? `${pct}%` : '-'}
                        </td>
                        <td className="px-6 py-4">
                          <span className="px-2.5 py-1 rounded-lg bg-[var(--color-purple)]/10 text-[var(--color-purple)] text-xs font-bold">#{r.rank ?? i + 1}</span>
                        </td>
                        <td className="px-6 py-4">
                          {violations === 0 ? (
                            <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-green-500/10 text-green-400 border border-green-500/20">Clean</span>
                          ) : (
                            <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-red-500/10 text-red-400 border border-red-500/20 flex items-center gap-1 w-fit">
                              <AlertTriangle className="w-3 h-3" /> {violations}
                            </span>
                          )}
                        </td>
                      </tr>
                    )
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    )
  }
  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <motion.h1 
            initial={{ opacity: 0, x: -10 }} 
            animate={{ opacity: 1, x: 0 }} 
            className="text-3xl font-bold text-[var(--text-primary)] tracking-tight"
          >
            Tests & Results
          </motion.h1>
          <p className="text-[var(--text-secondary)] text-sm mt-1 font-medium">{tests.length} tests conducted</p>
        </div>
        <div className="flex items-center gap-3 flex-wrap">
          <div className="relative">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-secondary)]" />
            <input
              type="text"
              placeholder="Search tests..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-10 pr-4 py-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm placeholder-[var(--text-secondary)]/50 outline-none focus:border-[var(--color-purple)] focus:bg-[var(--bg-surface)] w-64 transition-all"
            />
          </div>
          {canManage && (
            <>
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={() => setAiModalOpen(true)}
                className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-gradient-to-r from-purple-500 to-cyan-500 text-white text-sm font-semibold shadow-lg shadow-purple-500/20 active:scale-95 transition-all"
              >
                <Brain className="w-5 h-5" /> Create AI Test
              </motion.button>
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={() => setModalOpen(true)}
                className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-[var(--bg-surface)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm font-semibold hover:border-[var(--border-strong)] transition-all"
              >
                <Plus className="w-5 h-5" /> Manual Test
              </motion.button>
            </>
          )}
        </div>
      </div>

      <div className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl overflow-hidden shadow-sm">
        <DataTable columns={columns} data={filtered} emptyMessage="No tests found" />
      </div>

      {/* AI Test Creator Modal */}
      <AITestCreatorModal
        isOpen={aiModalOpen}
        onClose={() => setAiModalOpen(false)}
        batches={batches}
        onTestCreated={fetchData}
      />

      {/* Create Manual Test Modal */}
      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title="Create Manual Test">
        <div className="space-y-4">
          <Input label="Test Title" placeholder="e.g. Physics Unit Test 1" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} />
          <Select label="Batch" placeholder={batchOptions.length > 0 ? "Select batch" : "No batches available (Create one first)"} options={batchOptions} value={form.batch_id} onChange={(e) => setForm({ ...form, batch_id: e.target.value })} disabled={batchOptions.length === 0} />
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1.5">Date</label>
              <input type="date" value={form.date} onChange={(e) => setForm({ ...form, date: e.target.value })} className="w-full px-4 py-2.5 rounded-xl bg-white/5 border border-white/10 text-white text-sm outline-none focus:border-purple-500/50" />
            </div>
            <Input label="Total Marks" type="number" value={form.total_marks} onChange={(e) => setForm({ ...form, total_marks: e.target.value })} />
          </div>
          <div className="flex justify-end gap-3 pt-4 border-t border-white/10">
            <button onClick={() => setModalOpen(false)} className="px-4 py-2 rounded-xl text-sm text-gray-400 hover:text-white hover:bg-white/5 transition-colors">Cancel</button>
            <button onClick={handleCreateTest} disabled={saving || !form.title.trim() || !form.batch_id} className="px-5 py-2 rounded-xl bg-gradient-to-r from-purple-500 to-blue-500 text-white text-sm font-medium disabled:opacity-50">
              {saving ? 'Creating...' : 'Create Test'}
            </button>
          </div>
        </div>
      </Modal>

      {/* Enter Results Modal */}
      <Modal isOpen={resultsModal} onClose={() => setResultsModal(false)} title={`Results: ${selectedTest?.title || ''}`} size="lg">
        <div className="space-y-4">
          <div className="bg-[var(--bg-app)]/50 p-4 rounded-xl border border-[var(--border-subtle)] text-xs text-[var(--text-secondary)] font-medium">
            Enter marks for each student (out of {selectedTest?.total_marks}). Ranks are calculated automatically based on score.
          </div>
          <div className="space-y-2 max-h-[50vh] overflow-y-auto pr-2 custom-scrollbar">
            {testStudents.length === 0 ? (
              <div className="text-center py-12 text-[var(--text-secondary)]">
                <FileText className="w-12 h-12 mx-auto mb-3 opacity-20" />
                <p>No students in this batch</p>
              </div>
            ) : (
              testStudents.map((student) => (
                <div key={student.id} className="flex items-center justify-between px-5 py-3 rounded-xl bg-[var(--bg-card)] border border-[var(--border-subtle)]/50 hover:border-[var(--color-purple)]/30 transition-all">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-[var(--bg-app)] flex items-center justify-center text-xs font-bold text-[var(--text-primary)] border border-[var(--border-subtle)]">
                      {student.name.charAt(0).toUpperCase()}
                    </div>
                    <span className="text-sm font-bold text-[var(--text-primary)]">{student.name}</span>
                  </div>
                  {role === 'admin' ? (
                    <span className="w-24 px-4 py-2 rounded-lg bg-[var(--bg-app)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm text-center font-bold inline-block">
                      {marks[student.id] !== undefined && marks[student.id] !== '' ? `${marks[student.id]} / ${selectedTest?.total_marks}` : '-'}
                    </span>
                  ) : (
                    <input
                      type="number"
                      min="0"
                      max={selectedTest?.total_marks || 100}
                      placeholder="Marks"
                      value={marks[student.id] ?? ''}
                      onChange={(e) => setMarks({ ...marks, [student.id]: e.target.value })}
                      className="w-24 px-4 py-2 rounded-lg bg-[var(--bg-app)] border border-[var(--border-subtle)] text-[var(--text-primary)] text-sm text-center font-bold outline-none focus:border-[var(--color-purple)] focus:ring-1 focus:ring-[var(--color-purple)]"
                    />
                  )}
                </div>
              ))
            )}
          </div>
          <div className="flex justify-between items-center pt-6 border-t border-[var(--border-subtle)]">
            <button
              onClick={downloadResultsPDF}
              className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-[var(--color-purple)]/10 text-[var(--color-purple)] hover:bg-[var(--color-purple)]/20 transition-all text-sm font-semibold active:scale-95"
            >
              <FileDown className="w-4 h-4" /> Download PDF
            </button>
            <div className="flex gap-3">
              <button
                onClick={() => setResultsModal(false)}
                className="px-6 py-2.5 rounded-xl text-sm font-bold text-[var(--text-secondary)] hover:text-[var(--text-primary)] hover:bg-[var(--bg-app)] transition-all"
              >
                {role === 'admin' ? 'Close' : 'Cancel'}
              </button>
              {role !== 'admin' && (
                <button
                  onClick={handleSaveResults}
                  disabled={saving}
                  className="px-8 py-2.5 rounded-xl bg-[var(--color-purple)] text-white text-sm font-bold shadow-lg shadow-purple-500/20 active:scale-95 disabled:opacity-50 transition-all"
                >
                  {saving ? 'Saving Results...' : 'Save All Results'}
                </button>
              )}
            </div>
          </div>
        </div>
      </Modal>
    </div>
  )
}

